const GEOGRAPHY_AQA_PRACTICE = {
  '1.1': {
    name: 'Water & Carbon Cycles',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two inputs to the drainage basin water cycle.', marks: 2, markScheme: '• Precipitation (1)\n• Energy from the sun / solar energy (1)' },
      { q: 'State two stores of carbon in the lithosphere.', marks: 2, markScheme: '• Fossil fuels e.g. coal, oil, gas (1)\n• Sedimentary rocks e.g. limestone / chalk (1)' },
      { q: 'Define the term "residence time" in relation to the water cycle.', marks: 2, markScheme: '• The average length of time (1)\n• That a water molecule spends in a particular store/reservoir (1)' },
      { q: 'State two ways in which water is transferred from the land to the atmosphere.', marks: 2, markScheme: '• Evaporation (1)\n• Transpiration / evapotranspiration (1)' },
      { q: 'Define the term "carbon sequestration".', marks: 3, markScheme: '• The process of capturing/removing carbon dioxide from the atmosphere (1)\n• And storing it in a long-term reservoir/sink (1)\n• E.g. oceans, soils, forests, geological formations (1)' },
      { q: 'State three factors that affect the rate of evapotranspiration.', marks: 3, markScheme: '• Temperature (1)\n• Wind speed (1)\n• Humidity / vegetation type / available moisture (1)' },
      { q: 'Outline the difference between throughflow and groundwater flow.', marks: 3, markScheme: '• Throughflow moves laterally through the soil (1)\n• Groundwater flow moves through permeable rock below the water table (1)\n• Throughflow is generally faster than groundwater flow (1)' },
      { q: 'State two reasons why deforestation affects the carbon cycle.', marks: 2, markScheme: '• Reduces photosynthesis so less CO2 is absorbed from the atmosphere (1)\n• Burning/decomposition of cleared vegetation releases stored carbon as CO2 (1)' },
      { q: 'Define the term "cryosphere".', marks: 2, markScheme: '• The parts of the Earth\'s surface where water is in solid/frozen form (1)\n• Including ice sheets, glaciers, sea ice, permafrost (1)' },
      { q: 'State two outputs from the drainage basin system.', marks: 2, markScheme: '• River discharge / channel flow to the sea (1)\n• Evapotranspiration (1)' },

      // 4-6 mark questions (15)
      { q: 'Describe the main stores and flows in the global water cycle.', marks: 4, markScheme: '• Oceans are the largest store holding ~97% of water (1)\n• Cryosphere/ice caps store freshwater in solid form (1)\n• Atmosphere stores water as vapour/droplets (1)\n• Flows include evaporation, precipitation, runoff, condensation (1)\n• Groundwater stored in aquifers below the water table (1)\n• Credit any valid stores or transfers, max 4 marks' },
      { q: 'Explain how urbanisation affects the storm hydrograph.', marks: 6, markScheme: '• Impermeable surfaces increase surface runoff (1)\n• Reduces infiltration and percolation (1)\n• This leads to a shorter lag time (1)\n• And a higher peak discharge (1)\n• Drains and sewers transport water quickly to the river channel (1)\n• Less interception as vegetation is removed (1)\n• Rising limb becomes steeper (1)\n• Overall flashier hydrograph response (1)\n• Credit annotated diagram, max 6 marks' },
      { q: 'Sketch and annotate a storm hydrograph to show the response of a drainage basin to a rainfall event.', marks: 6, diagram: true, markScheme: '• Correctly drawn axes: discharge (y) and time (x) (1)\n• Rainfall bar chart shown above (1)\n• Rising limb correctly drawn (1)\n• Peak discharge labelled (1)\n• Falling/recession limb correctly drawn (1)\n• Lag time correctly identified between peak rainfall and peak discharge (1)\n• Baseflow shown (1)\n• Credit any additional valid annotations, max 6 marks' },
      { q: 'Explain how the carbon cycle operates in tropical rainforest ecosystems.', marks: 6, markScheme: '• High rates of photosynthesis absorb large amounts of atmospheric CO2 (1)\n• Carbon stored in biomass — large trees, dense vegetation (1)\n• Rapid decomposition in warm, humid conditions returns carbon to the soil (1)\n• Carbon in soil organic matter / humus (1)\n• Respiration by plants and organisms releases CO2 (1)\n• Nutrient cycling is rapid due to high temperatures (1)\n• Deforestation disrupts this cycle by releasing stored carbon (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain how changes in one element of the water cycle can have knock-on effects on other elements.', marks: 6, markScheme: '• Increased temperatures increase evaporation rates (1)\n• More atmospheric moisture leads to greater precipitation (1)\n• This can increase river discharge and flood risk (1)\n• Melting of ice stores reduces albedo effect creating positive feedback (1)\n• Deforestation reduces interception and transpiration (1)\n• Leading to increased surface runoff and reduced soil moisture stores (1)\n• Illustrates the interconnected nature of the system — change to inputs/outputs affects stores and flows (1)\n• Credit any valid chain of knock-on effects, max 6 marks' },
      { q: 'Describe the role of the oceans in the carbon cycle.', marks: 4, markScheme: '• Oceans are the largest carbon sink, absorbing CO2 from the atmosphere (1)\n• CO2 dissolves in surface water forming carbonic acid (1)\n• Marine organisms use carbon for shells/skeletons — biological pump (1)\n• Dead organisms sink and carbon stored in deep ocean sediments (1)\n• Ocean currents redistribute dissolved carbon — thermohaline circulation (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain the concept of a positive feedback loop in the water cycle, using a named example.', marks: 4, markScheme: '• A positive feedback amplifies/reinforces the initial change (1)\n• Example: ice-albedo feedback — as ice melts, darker surfaces are exposed (1)\n• Darker surfaces absorb more solar radiation (1)\n• This causes further warming and more ice melt (1)\n• Or: permafrost melting releases methane, causing more warming (1)\n• Credit any valid positive feedback example, max 4 marks' },
      { q: 'Explain how human activities have altered the carbon cycle over the past 200 years.', marks: 6, markScheme: '• Burning fossil fuels releases carbon stored over millions of years (1)\n• This transfers carbon from lithosphere to atmosphere rapidly (1)\n• Deforestation reduces the terrestrial carbon sink (1)\n• Agriculture changes soil carbon stores through ploughing (1)\n• Cement production releases CO2 from limestone (1)\n• Atmospheric CO2 has risen from ~280ppm to over 420ppm (1)\n• Enhanced greenhouse effect leading to global warming (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Describe how water is stored and transferred in a river drainage basin.', marks: 4, markScheme: '• Water stored in soil moisture (1)\n• Stored in groundwater / aquifers below the water table (1)\n• Transferred by infiltration from surface into soil (1)\n• Throughflow moves water laterally through the soil (1)\n• Channel flow / river discharge carries water to the sea (1)\n• Surface runoff / overland flow during intense rain (1)\n• Credit any valid stores or transfers, max 4 marks' },
      { q: 'Draw and label a diagram to show the main components of the global carbon cycle.', marks: 6, diagram: true, markScheme: '• Atmosphere store shown with approximate CO2 value (1)\n• Terrestrial stores identified: biomass, soil, lithosphere (1)\n• Ocean store identified (1)\n• Flows shown: photosynthesis, respiration (1)\n• Flows shown: combustion, decomposition (1)\n• Flows shown: ocean absorption/release (1)\n• Arrows showing correct direction of flows (1)\n• Credit any valid additional detail, max 6 marks' },
      { q: 'Explain how permafrost thawing could create a climate feedback loop.', marks: 5, markScheme: '• Permafrost contains large stores of frozen organic carbon/methane (1)\n• Rising global temperatures cause permafrost to thaw (1)\n• Decomposition of organic matter releases CO2 and methane (1)\n• Methane is a potent greenhouse gas — more powerful than CO2 (1)\n• This causes further warming, which causes more thawing — positive feedback (1)\n• Could release gigatonnes of carbon, accelerating climate change (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Describe how soil type and geology affect the shape of the storm hydrograph.', marks: 4, markScheme: '• Permeable rocks (e.g. chalk, sandstone) allow infiltration, reducing peak discharge (1)\n• Impermeable rocks (e.g. clay, granite) increase surface runoff (1)\n• Sandy soils allow rapid infiltration — longer lag time (1)\n• Clay soils have low infiltration rates — shorter lag time, higher peak (1)\n• Saturated soils reduce infiltration capacity (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain why the water cycle is described as a closed system at the global scale but an open system at the drainage basin scale.', marks: 4, markScheme: '• At global scale, no water is added to or lost from the Earth system (1)\n• Energy enters and leaves but the total amount of water remains constant (1)\n• At drainage basin scale, water enters as precipitation (input) (1)\n• And leaves as river discharge and evapotranspiration (outputs) (1)\n• Therefore the drainage basin has both inputs and outputs — open system (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain two ways in which forests act as carbon sinks.', marks: 4, markScheme: '• Photosynthesis absorbs CO2 from the atmosphere (1)\n• Carbon is stored in tree biomass — trunks, branches, leaves, roots (1)\n• Leaf litter and dead organic matter add carbon to the soil (1)\n• Soil organic matter stores carbon for long periods (1)\n• Credit any two explained ways, max 4 marks' },
      { q: 'Describe the physical factors that influence the water balance of a drainage basin.', marks: 5, markScheme: '• Climate — temperature and precipitation patterns (1)\n• Season — affects evapotranspiration rates and snow storage (1)\n• Geology — permeability determines groundwater recharge (1)\n• Relief/slope — affects runoff speed and infiltration (1)\n• Vegetation — intercepts precipitation and increases transpiration (1)\n• Soil type — affects infiltration and throughflow rates (1)\n• Credit any valid physical factors, max 5 marks' },

      // 8-9 mark questions (10)
      { q: 'Assess the impact of climate change on the global water cycle.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed, well-developed assessment with clear links between climate change and water cycle processes. Evaluative conclusion.\nLevel 2 (4-6 marks): Some developed points with partial assessment. Links between climate change and water cycle are evident.\nLevel 1 (1-3 marks): Basic points with limited development.\n\nIndicative content:\n• Increased global temperatures accelerate evaporation rates\n• More atmospheric moisture leads to intensified precipitation events\n• Changing distribution — some areas wetter, others drier\n• Melting glaciers and ice sheets reduce cryospheric stores\n• Rising sea levels alter coastal water systems\n• Permafrost thawing releases stored water and methane\n• Positive feedback loops amplify changes\n• Shifts in monsoon patterns and jet stream\n• Increased frequency of droughts and floods\n• Changes to snowmelt timing affecting river regimes' },
      { q: 'Explain how the water and carbon cycles are linked within a tropical rainforest ecosystem.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of links between both cycles within the rainforest, with clear understanding of interconnections.\nLevel 2 (4-6 marks): Some valid links identified between cycles with partial development.\nLevel 1 (1-3 marks): Basic points about one or both cycles with limited linkage.\n\nIndicative content:\n• Photosynthesis uses water and absorbs CO2 — linking both cycles\n• Transpiration returns water to atmosphere while releasing oxygen\n• High rainfall supports dense biomass — large carbon store\n• Decomposition in moist conditions releases carbon to soil and atmosphere\n• Soil moisture enables root uptake and nutrient cycling\n• Deforestation disrupts both cycles simultaneously\n• Evapotranspiration generates convectional rainfall — recycling moisture\n• Dissolved carbon transferred through soil water and groundwater\n• River systems transport dissolved organic carbon to oceans' },
      { q: 'Assess the effectiveness of strategies to manage the carbon cycle at local and global scales.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple strategies at different scales with evaluative comparison of effectiveness.\nLevel 2 (4-6 marks): Some strategies described with partial assessment.\nLevel 1 (1-3 marks): Basic identification of strategies with limited assessment.\n\nIndicative content:\n• Carbon capture and storage (CCS) technology\n• Afforestation and reforestation programmes\n• International agreements e.g. Paris Agreement\n• Carbon trading and carbon taxes\n• Renewable energy transition reducing fossil fuel combustion\n• Soil carbon management in agriculture\n• Blue carbon — protecting mangroves and seagrass\n• Scale of implementation — local actions vs global cooperation\n• Effectiveness limited by political will and economic costs\n• Technological limitations of CCS\n• Time lag between action and measurable impact' },
      { q: 'Explain the factors that influence the shape and characteristics of a storm hydrograph.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple factors with clear links to hydrograph characteristics. Well-developed points.\nLevel 2 (4-6 marks): Several factors explained with some links to hydrograph shape.\nLevel 1 (1-3 marks): Basic identification of factors with limited explanation.\n\nIndicative content:\n• Basin size — larger basins have longer lag times\n• Basin shape — circular basins produce flashier hydrographs\n• Drainage density — higher density leads to faster response\n• Slope/relief — steeper slopes increase runoff speed\n• Land use — urbanisation creates flashier response\n• Soil type — clay vs sandy soils affect infiltration\n• Geology — permeable vs impermeable rock\n• Vegetation cover — interception reduces peak discharge\n• Antecedent moisture conditions — saturated soil reduces infiltration\n• Rainfall intensity and duration' },
      { q: 'Assess the role of the oceans in regulating the global carbon cycle.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed, well-developed assessment of oceanic role with clear understanding of processes and evaluation of significance.\nLevel 2 (4-6 marks): Some developed points about oceanic carbon processes.\nLevel 1 (1-3 marks): Basic points about oceans and carbon.\n\nIndicative content:\n• Oceans absorb approximately 25-30% of anthropogenic CO2\n• Physical pump — CO2 dissolves in cold surface waters\n• Biological pump — phytoplankton photosynthesis\n• Marine organisms use carbon for shells (calcium carbonate)\n• Deep ocean stores carbon for centuries\n• Thermohaline circulation transports dissolved carbon\n• Ocean acidification as CO2 absorption increases\n• Warming oceans may reduce absorption capacity\n• Coral reef destruction reduces biological carbon cycling\n• Balance between ocean as sink and potential source' },
      { q: 'Explain how water and carbon cycle processes operate differently in a temperate deciduous forest compared to a hot desert.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed comparison of both cycles in both biomes with clear contrasts.\nLevel 2 (4-6 marks): Some valid comparisons with partial development.\nLevel 1 (1-3 marks): Basic points about one or both biomes.\n\nIndicative content:\n• Temperate forest has higher precipitation and lower evaporation than desert\n• Greater infiltration and throughflow in forest soils vs minimal in desert\n• Deciduous forest has large biomass carbon store, desert has very little\n• Seasonal leaf fall creates soil carbon store in forest\n• High rates of photosynthesis in forest vs very limited in desert\n• Desert has low decomposition rates — limited moisture\n• Transpiration rates much higher in forested areas\n• Desert soils have very low organic carbon content\n• Different hydrological responses — forest buffered, desert flashy\n• Carbon stored in desert soils as inorganic carbonates' },
      { q: 'Assess the impact of land use change on the water cycle in a named drainage basin or area you have studied.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment using specific named example with clear links between land use change and water cycle impacts.\nLevel 2 (4-6 marks): Some valid points with reference to a named area.\nLevel 1 (1-3 marks): Basic/generic points with limited reference to a specific area.\n\nIndicative content:\n• Named drainage basin/area with specific land use changes\n• Deforestation reduces interception and transpiration\n• Urbanisation increases impermeable surfaces and surface runoff\n• Agricultural drainage alters soil water stores\n• Reservoir construction changes natural flow regimes\n• Increased flood risk from land use change\n• Reduced groundwater recharge from impermeable surfaces\n• Changes to sediment load and water quality\n• Specific data/evidence from the named area\n• Assessment of significance of different land use changes' },
      { q: 'Explain how natural and human factors have caused changes in the carbon cycle over geological time.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation covering both natural and human factors over different timescales.\nLevel 2 (4-6 marks): Some factors explained with partial development.\nLevel 1 (1-3 marks): Basic points with limited explanation.\n\nIndicative content:\n• Volcanic eruptions release CO2 from the lithosphere\n• Weathering of silicate rocks absorbs CO2 over long timescales\n• Formation of fossil fuels locked carbon in lithosphere over millions of years\n• Carboniferous period — vast forests stored carbon as coal\n• Natural glacial-interglacial cycles altered atmospheric CO2\n• Milankovitch cycles influenced natural climate variation\n• Human burning of fossil fuels since Industrial Revolution\n• Deforestation and agriculture in the last 10,000 years\n• Cement production and industrial processes\n• Rate of human change is unprecedented compared to natural changes' },
      { q: 'Explain the causes and consequences of changes to the cryospheric store of water.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of both causes and consequences with clear understanding of interconnections.\nLevel 2 (4-6 marks): Some valid points about causes and/or consequences.\nLevel 1 (1-3 marks): Basic identification of causes or consequences.\n\nIndicative content:\n• Global warming causing glacial retreat and ice sheet thinning\n• Arctic sea ice declining in extent and thickness\n• Permafrost thawing in high latitudes\n• Consequences: sea level rise from ice sheet melt (Greenland, Antarctica)\n• Reduced albedo creates positive feedback for further warming\n• Changed river regimes in glacially-fed rivers\n• Initially increased meltwater then long-term reduction\n• Loss of freshwater stores for populations dependent on glacial melt\n• Thermohaline circulation disruption from freshwater input\n• Release of methane from thawing permafrost\n• Habitat loss for Arctic species' },
      { q: 'Assess the extent to which natural climate variability can explain recent changes in the water and carbon cycles.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment considering both natural variability and anthropogenic factors with evaluative conclusion.\nLevel 2 (4-6 marks): Some consideration of natural and/or human factors.\nLevel 1 (1-3 marks): Basic points with limited assessment.\n\nIndicative content:\n• Natural variability: Milankovitch cycles, solar output changes, volcanic eruptions\n• El Nino/La Nina affects global precipitation and carbon cycling\n• However, rate and scale of recent changes exceed natural variability\n• CO2 levels far higher than any natural variation in 800,000 years\n• Isotopic evidence shows fossil fuel origin of additional CO2\n• Natural factors alone cannot explain observed warming trend\n• Human factors: fossil fuel combustion, deforestation, land use change\n• IPCC attribution studies\n• Assessment that human factors are the dominant cause\n• Natural factors modulate but do not drive recent trends' },

      // 12-20 mark questions (5)
      { q: 'Evaluate the role of human activity in modifying the carbon cycle. To what extent should carbon cycle management be a global priority?', marks: 20, markScheme: 'Level 4 (16-20 marks): Detailed, evaluative response with thorough understanding of human impacts on the carbon cycle. Well-structured argument with substantiated conclusion about global priorities.\nLevel 3 (11-15 marks): Clear evaluation of human impacts with some depth. Developed argument about priorities with partial conclusion.\nLevel 2 (6-10 marks): Some relevant points about human activity and the carbon cycle. Limited evaluation or argument.\nLevel 1 (1-5 marks): Basic points with minimal evaluation.\n\nIndicative content:\n• Fossil fuel combustion — transferring lithospheric carbon to atmosphere\n• Deforestation — reducing terrestrial carbon sinks\n• Agriculture — altering soil carbon stores\n• Industrial processes — cement, steel production\n• Land use change over centuries\n• Scale of human impact vs natural processes\n• Evidence of atmospheric CO2 increase (Keeling Curve, ice cores)\n• Consequences: enhanced greenhouse effect, ocean acidification\n• Management strategies: international agreements, carbon trading, CCS, afforestation\n• Challenges: economic costs, political barriers, equity issues\n• Different perspectives: developed vs developing nations\n• Urgency: tipping points and irreversible changes\n• Evaluation of whether management is achievable at required scale\n• Conclusion reflecting on the balance of evidence' },
      { q: 'Discuss the extent to which climate change is altering the balance between water cycle stores and flows at a global scale.', marks: 20, markScheme: 'Level 4 (16-20 marks): Comprehensive discussion with detailed understanding of how climate change affects multiple stores and flows. Well-evidenced evaluation of the extent of change.\nLevel 3 (11-15 marks): Good discussion of several stores/flows with some evaluation of extent.\nLevel 2 (6-10 marks): Some relevant points about climate change and the water cycle.\nLevel 1 (1-5 marks): Basic, limited points.\n\nIndicative content:\n• Cryospheric stores: ice sheets melting, glacial retreat, permafrost thaw\n• Atmospheric stores: increased water vapour content\n• Ocean stores: thermal expansion, sea level rise\n• Groundwater depletion exacerbated by changing precipitation\n• Intensified hydrological cycle — more evaporation and precipitation\n• Regional redistribution of precipitation patterns\n• More extreme events — droughts and floods\n• Positive feedback loops: ice-albedo, water vapour\n• Changes to monsoon systems and jet stream patterns\n• Evidence from specific regions/case studies\n• Scale and rate of change relative to natural variability\n• Tipping points and thresholds in the water cycle\n• Management implications and adaptation strategies\n• Evaluative conclusion on the extent and significance of changes' },
      { q: '"The water and carbon cycles are so interconnected that they should be studied as one system." Discuss this statement with reference to specific environments.', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated discussion with detailed examples of interconnections in specific environments. Balanced evaluation of the statement with well-reasoned conclusion.\nLevel 3 (11-15 marks): Good discussion of interconnections in named environments with partial evaluation.\nLevel 2 (6-10 marks): Some relevant points about links between cycles.\nLevel 1 (1-5 marks): Basic, limited points.\n\nIndicative content:\n• Photosynthesis and transpiration link both cycles in forests\n• Tropical rainforest: high rainfall drives carbon cycling, dense biomass recycles moisture\n• Oceans: carbon dissolved in water, biological pump links both cycles\n• Peatlands: waterlogged conditions preserve carbon, drainage releases it\n• Permafrost: frozen water preserves carbon, thawing disrupts both cycles\n• Weathering: water dissolves carbon in rocks\n• Soil processes: water enables decomposition and carbon release\n• Climate change affects both cycles simultaneously\n• However, cycles also have independent processes and stores\n• Different timescales of operation (geological vs annual)\n• Practical value of studying them together vs separately\n• Conclusion evaluating the degree of interconnection' },
      { q: 'To what extent does the study of water and carbon cycles help us understand and manage the impacts of climate change?', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough evaluation of how understanding both cycles informs climate change management. Detailed examples and substantiated conclusion about extent of usefulness.\nLevel 3 (11-15 marks): Good discussion of understanding and management with some evaluation.\nLevel 2 (6-10 marks): Some relevant points with limited evaluation.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Understanding carbon cycle identifies sources and sinks\n• Water cycle knowledge predicts flood/drought risk\n• Models of both cycles inform climate projections\n• Carbon cycle understanding → mitigation strategies (CCS, afforestation)\n• Water cycle understanding → adaptation strategies (flood management, water conservation)\n• Feedback loops must be understood to predict tipping points\n• Limitations of current understanding and models\n• Uncertainty in projections despite improved knowledge\n• Political and economic barriers to acting on scientific understanding\n• Knowledge of cycles helps set targets (e.g. 1.5°C/2°C)\n• However, management requires political will not just scientific understanding\n• Scale mismatch between global cycles and national policy\n• Conclusion on the extent to which knowledge translates to effective management' },
      { q: 'Evaluate the relative importance of natural and human factors in causing changes to the water and carbon cycles over the last 200 years.', marks: 20, markScheme: 'Level 4 (16-20 marks): Balanced, evaluative discussion of both natural and human factors with clear assessment of relative importance. Well-evidenced conclusion.\nLevel 3 (11-15 marks): Good coverage of factors with some assessment of relative importance.\nLevel 2 (6-10 marks): Some relevant points about natural and/or human factors.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Natural factors: volcanic eruptions, solar variability, ENSO cycles, orbital variations\n• Human factors: fossil fuel combustion, deforestation, urbanisation, agriculture, damming\n• Scale of human impact: CO2 from ~280 to 420+ ppm since 1800\n• Industrial Revolution as turning point for both cycles\n• Water cycle: abstraction, dam construction, land use change, irrigation\n• Carbon cycle: ~40 billion tonnes CO2 emitted annually by humans\n• Natural factors still operate but are modulated by human activity\n• Attribution science — IPCC conclusions on human dominance\n• Evidence: isotopic ratios, ice cores, Keeling Curve\n• Rate of change unprecedented in geological record\n• Interaction between natural and human factors (feedbacks)\n• Regional variations in relative importance\n• Conclusion: human factors dominant but natural factors still relevant' },
    ],
  },
  '1.2': {
    name: 'Coastal Systems & Landscapes',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two types of sub-aerial weathering that affect coastlines.', marks: 2, markScheme: '• Freeze-thaw / frost shattering (1)\n• Chemical weathering e.g. carbonation, oxidation (1)\n• Or biological weathering, salt crystallisation, wetting and drying (1)' },
      { q: 'Define the term "longshore drift".', marks: 2, markScheme: '• The movement/transport of sediment along a coastline (1)\n• By the action of waves approaching at an angle / swash and backwash at different angles (1)' },
      { q: 'State two characteristics of constructive waves.', marks: 2, markScheme: '• Low wave height / long wavelength (1)\n• Strong swash, weak backwash / low frequency (6-8 per minute) (1)' },
      { q: 'Define the term "concordant coastline".', marks: 2, markScheme: '• A coastline where rock strata/geology runs parallel to the coast (1)\n• Producing a relatively straight/even coastline (1)' },
      { q: 'State three processes of coastal erosion.', marks: 3, markScheme: '• Hydraulic action / wave quarrying (1)\n• Abrasion / corrasion (1)\n• Attrition / corrosion (solution) (1)' },
      { q: 'Define the term "sediment cell".', marks: 3, markScheme: '• A largely self-contained stretch of coastline (1)\n• Within which the movement of sediment is contained (1)\n• With inputs, transfers, stores and outputs of sediment (1)' },
      { q: 'State two sources of sediment for coastal environments.', marks: 2, markScheme: '• River/fluvial input (1)\n• Cliff erosion / longshore drift from adjacent coastline / offshore sources / wind-blown (1)' },
      { q: 'Outline the difference between abrasion and attrition as processes of coastal erosion.', marks: 3, markScheme: '• Abrasion is when waves throw sediment/rocks against the cliff face (1)\n• This wears away/erodes the rock surface (1)\n• Attrition is when rock fragments/sediment collide with each other (1)\n• Becoming smaller, smoother and more rounded (1)\n• Max 3 marks' },
      { q: 'State two factors that determine whether a coast is erosional or depositional.', marks: 2, markScheme: '• Wave energy — high energy coasts tend to be erosional (1)\n• Sediment supply — abundant sediment promotes deposition (1)\n• Or: rock type/geology, coastal orientation, presence of structures (1)' },
      { q: 'Define the term "fetch".', marks: 2, markScheme: '• The distance of open water/sea (1)\n• Over which the wind blows to generate waves (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain the formation of a wave-cut platform.', marks: 6, markScheme: '• Waves attack the base of the cliff (1)\n• Erosion processes: hydraulic action, abrasion (1)\n• A wave-cut notch is formed at the base of the cliff (1)\n• The cliff above becomes unsupported and collapses (1)\n• The cliff retreats leaving a gently sloping rock platform (1)\n• The platform becomes wider as the cliff retreats further (1)\n• Eventually wave energy is dissipated across the wide platform (1)\n• Sub-aerial weathering also contributes to cliff retreat (1)\n• Credit annotated diagram, max 6 marks' },
      { q: 'Explain the formation of a spit with reference to the processes involved.', marks: 6, markScheme: '• Longshore drift transports sediment along the coast (1)\n• Where the coastline changes direction, sediment continues to be deposited (1)\n• A finger of land/ridge of sand/shingle extends into the sea (1)\n• Prevailing wind/wave direction determines the orientation (1)\n• A curved/hooked end may form due to secondary wave direction/refraction (1)\n• Sheltered area behind the spit allows mud/silt deposition — salt marsh forms (1)\n• The spit does not grow across the entire bay as river currents prevent this (1)\n• Credit annotated diagram, max 6 marks' },
      { q: 'Draw an annotated diagram to show the formation of a headland and bay coastline.', marks: 4, diagram: true, markScheme: '• Diagram shows alternating bands of hard and soft rock (1)\n• Rock bands running perpendicular to coastline (discordant) (1)\n• Bays formed in weaker/softer rock that erodes faster (1)\n• Headlands remain as more resistant rock protrudes (1)\n• Wave refraction around headlands concentrating energy shown (1)\n• Max 4 marks' },
      { q: 'Explain the processes involved in the formation of sand dunes.', marks: 6, markScheme: '• Wind transports dry sand by saltation from the beach (1)\n• Obstacles/debris trap sand causing accumulation (1)\n• Embryo dunes form closest to the sea (1)\n• Pioneer plants e.g. sea couch grass colonise and stabilise sand (1)\n• Marram grass on yellow/mobile dunes traps more sand (1)\n• Dunes grow in size and become more vegetated further from the shore (1)\n• Succession occurs with increasingly diverse plant communities (1)\n• Soil develops, organic matter increases, pH decreases inland (1)\n• Credit annotated diagram, max 6 marks' },
      { q: 'Explain how wave refraction affects the distribution of wave energy along a coastline with headlands and bays.', marks: 4, markScheme: '• As waves approach the coast, they are slowed by friction in shallow water near headlands (1)\n• Wave crests bend/refract to become more parallel to the coastline (1)\n• Wave energy is concentrated/focused on the headlands (1)\n• Wave energy is dispersed/spread out in the bays (1)\n• This leads to erosion on headlands and deposition in bays (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain the formation of a stack from a headland.', marks: 6, markScheme: '• Waves attack lines of weakness / joints / faults in the headland (1)\n• Hydraulic action and abrasion enlarge cracks (1)\n• A cave forms on one or both sides of the headland (1)\n• Caves on both sides erode through to form an arch (1)\n• The roof of the arch is weakened by weathering and wave action (1)\n• The roof collapses leaving an isolated stack (1)\n• The stack may be further eroded to form a stump (1)\n• Credit annotated diagram, max 6 marks' },
      { q: 'Describe the characteristics and formation of a bar and lagoon.', marks: 5, markScheme: '• A bar is formed when a spit grows across an entire bay (1)\n• Longshore drift transports sediment across the bay entrance (1)\n• The bar connects two headlands creating an enclosed body of water (1)\n• The enclosed water body behind the bar is a lagoon (1)\n• Over time the lagoon may become freshwater from river input (1)\n• Examples: Slapton Ley (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain how geology influences coastal landforms.', marks: 6, markScheme: '• Rock type determines resistance to erosion (1)\n• Hard rocks (granite, basalt) erode slowly forming headlands and cliffs (1)\n• Soft rocks (clay, sand) erode quickly forming bays and low cliffs (1)\n• Concordant coastlines have rock parallel to the coast (1)\n• Discordant coastlines have alternating rock types perpendicular to the coast (1)\n• Rock structure — joints, faults, bedding planes are exploited by erosion (1)\n• Dip of rock strata affects cliff profile (seaward dip = gentle, landward dip = steep) (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Describe the landform characteristics of an estuary.', marks: 4, markScheme: '• A tidal inlet where a river meets the sea (1)\n• Wide, funnel-shaped mouth (1)\n• Mudflats and salt marshes on the margins (1)\n• Channels that shift with tidal flow (1)\n• Mix of freshwater and saltwater — brackish conditions (1)\n• Fine sediment (silt, clay) deposited by flocculation (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Sketch a cross-section of a sand dune system from the beach to inland, and label the key features.', marks: 6, diagram: true, markScheme: '• Beach/foreshore shown (1)\n• Embryo dunes shown — small, near sea (1)\n• Fore/yellow dunes — larger, with marram grass (1)\n• Grey/fixed dunes — more vegetated, further inland (1)\n• Dune slacks — low-lying wet areas between ridges (1)\n• General increase in height and vegetation moving inland shown (1)\n• Climax vegetation / woodland at rear (1)\n• Credit any valid labels/annotations, max 6 marks' },
      { q: 'Explain the causes and consequences of coastal flooding.', marks: 6, markScheme: '• Storm surges caused by low atmospheric pressure and strong onshore winds (1)\n• High tides combined with storm conditions (1)\n• Sea level rise increases baseline flood risk (1)\n• Low-lying coastlines are most vulnerable (1)\n• Consequences: loss of life and property damage (1)\n• Saltwater contamination of agricultural land and freshwater sources (1)\n• Coastal erosion accelerated by flooding events (1)\n• Infrastructure damage — roads, railways, utilities (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the role of mass movement in coastal retreat.', marks: 5, markScheme: '• Mass movement is the downslope movement of material under gravity (1)\n• Rockfall: fragments break from steep cliffs due to weathering (1)\n• Rotational slumping: saturated clay cliffs slide along curved surface (1)\n• Mudflows/landslides on weaker geology after heavy rain (1)\n• Marine erosion at cliff base creates instability triggering mass movement (1)\n• Mass movement supplies sediment to the beach (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain how eustatic and isostatic changes affect sea level.', marks: 4, markScheme: '• Eustatic change is a global change in sea level (1)\n• Caused by changes in the volume of water e.g. melting ice sheets (1)\n• Isostatic change is a local change due to land rising or sinking (1)\n• Post-glacial rebound — land rises after weight of ice removed (1)\n• Both processes create emergent or submergent coastlines (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Describe the processes of coastal transportation.', marks: 4, markScheme: '• Traction — large/heavy sediment rolled along the seabed (1)\n• Saltation — smaller particles bounced along the seabed (1)\n• Suspension — fine particles carried within the water (1)\n• Solution — dissolved minerals carried in the water (1)\n• Longshore drift moves sediment along the coast (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain how vegetation succession occurs on sand dunes.', marks: 5, markScheme: '• Pioneer species (sea couch, sea rocket) colonise embryo dunes (1)\n• These plants tolerate salt spray and lack of water/nutrients (1)\n• Marram grass dominates yellow dunes — deep roots, traps sand (1)\n• Humus accumulates, soil moisture increases (1)\n• Grey dunes support a wider range of species (heather, gorse) (1)\n• Eventually climax community of woodland develops (1)\n• Each stage modifies the environment for the next — ecological succession (1)\n• Credit any valid points, max 5 marks' },

      // 8-9 mark questions (10)
      { q: 'Assess the effectiveness of hard engineering strategies for managing coastal erosion.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple strategies with clear evaluation of effectiveness, including advantages and limitations.\nLevel 2 (4-6 marks): Some strategies described with partial assessment.\nLevel 1 (1-3 marks): Basic identification of strategies.\n\nIndicative content:\n• Sea walls — absorb wave energy but expensive (£5000-10000/m) and can reflect wave energy\n• Groynes — trap sediment but starve downdrift areas\n• Rock armour/rip-rap — absorbs energy, cheaper but unsightly\n• Gabions — wire cages with rocks, moderate effectiveness\n• Offshore breakwaters — reduce wave energy reaching shore\n• Each strategy has different cost-benefit ratios\n• Hard engineering often transfers problems elsewhere\n• Environmental impacts on natural processes\n• May not be sustainable long-term with sea level rise\n• Comparison of effectiveness for different coastal contexts' },
      { q: 'Explain how coastal landscapes are shaped by the interaction of physical processes over time.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation showing how multiple processes interact to create and modify landforms over different timescales.\nLevel 2 (4-6 marks): Some processes explained with links to landscape development.\nLevel 1 (1-3 marks): Basic identification of processes or landforms.\n\nIndicative content:\n• Marine erosion (hydraulic action, abrasion, attrition) creates erosional landforms\n• Sub-aerial weathering weakens cliff face\n• Mass movement contributes to cliff retreat\n• Deposition creates constructive landforms (beaches, spits, bars)\n• Longshore drift transports and redistributes sediment\n• Wave refraction concentrates and disperses energy\n• Geology determines resistance and landform type\n• Sea level changes create emergent/submergent features\n• Vegetation stabilises depositional features\n• Time allows progression from caves to arches to stacks\n• Dynamic equilibrium — coastline constantly adjusting' },
      { q: 'Assess the role of sediment supply in shaping coastal landscapes.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of sediment sources, transfers and their impact on landscape with evaluation.\nLevel 2 (4-6 marks): Some valid points about sediment and landscape with partial assessment.\nLevel 1 (1-3 marks): Basic points about sediment.\n\nIndicative content:\n• Sources: cliff erosion, river input, offshore, longshore drift, wind\n• Sediment budget concept — balance of inputs and outputs\n• Positive budget → accretion, beach growth, spit development\n• Negative budget → erosion, beach loss, cliff retreat\n• Sediment cells as management units\n• Longshore drift as key transfer mechanism\n• Human interference with sediment supply (groynes, dams)\n• Different sediment types create different features\n• Seasonal changes in sediment movement\n• Assessment of relative importance of different sources' },
      { q: 'Explain the formation and characteristics of salt marshes.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of formation processes and characteristics with clear understanding of succession.\nLevel 2 (4-6 marks): Some valid points about salt marsh formation.\nLevel 1 (1-3 marks): Basic identification of features.\n\nIndicative content:\n• Form in sheltered, low-energy environments (behind spits, in estuaries)\n• Fine sediment (silt, clay) deposited at high tide\n• Mudflats develop as sediment accumulates\n• Pioneer plants (Salicornia, Spartina) colonise mudflats\n• Plants trap more sediment, raising the surface level\n• Creek systems form for tidal drainage\n• Succession leads to increasingly diverse plant communities\n• Higher marsh flooded less frequently — different species\n• High organic content in soils\n• Important habitats for birds and marine organisms\n• Role in coastal protection and carbon storage' },
      { q: 'Assess the arguments for and against managed retreat as a coastal management strategy.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment of arguments for and against with evaluative conclusion. Use of specific examples.\nLevel 2 (4-6 marks): Some arguments identified with partial assessment.\nLevel 1 (1-3 marks): Basic points about managed retreat.\n\nIndicative content:\nFor:\n• More sustainable and cost-effective long-term\n• Allows natural processes to operate\n• Creates natural flood defence (salt marsh)\n• Habitat creation for wildlife\n• Reduces maintenance costs of hard defences\nAgainst:\n• Loss of homes, farmland, livelihoods\n• Compensation costs can be high\n• Emotional attachment to place\n• Political opposition from affected communities\n• Heritage and cultural loss\n• Named example e.g. Medmerry, Wallasea Island\n• Evaluation of when managed retreat is/is not appropriate' },
      { q: 'Explain how climate change is likely to affect coastal systems and landscapes.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple impacts with clear understanding of processes.\nLevel 2 (4-6 marks): Some valid impacts explained with partial development.\nLevel 1 (1-3 marks): Basic identification of impacts.\n\nIndicative content:\n• Sea level rise from thermal expansion and ice melt\n• Increased erosion rates on vulnerable coastlines\n• More frequent and intense storm events\n• Changes to wave patterns and dominant wave direction\n• Increased flooding of low-lying coastal areas\n• Disruption to sediment supply and transport patterns\n• Coral bleaching and reef degradation\n• Salt marsh migration or loss\n• Changes to coastal vegetation and habitats\n• Need for adaptation of coastal management strategies\n• Coastal squeeze — habitats trapped between rising sea and defences' },
      { q: 'Assess the sustainability of soft engineering approaches to coastal management.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple soft engineering strategies with clear evaluation of sustainability.\nLevel 2 (4-6 marks): Some strategies discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of strategies.\n\nIndicative content:\n• Beach nourishment — adds sediment but requires repeat applications\n• Dune stabilisation — planting marram grass, fencing\n• Managed retreat / realignment — allows natural processes\n• Marsh creation — natural flood defence\n• Cliff drainage — reduces mass movement risk\n• Generally cheaper than hard engineering\n• Works with natural processes rather than against them\n• Less visually intrusive\n• But may not provide immediate protection\n• Effectiveness varies with coastal context\n• Requires ongoing monitoring and maintenance\n• More sustainable approach to sea level rise' },
      { q: 'Explain the factors that influence the rate of cliff retreat at a named stretch of coastline.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of multiple factors at a named coastline with clear understanding of interactions.\nLevel 2 (4-6 marks): Some factors explained with reference to named location.\nLevel 1 (1-3 marks): Basic points with limited reference to named location.\n\nIndicative content:\n• Named coastline e.g. Holderness, Dorset\n• Rock type and resistance — soft boulder clay vs hard chalk\n• Wave energy — fetch, wind direction, exposure\n• Beach width — wider beaches dissipate wave energy\n• Sub-aerial processes — weathering, groundwater seepage\n• Mass movement — slumping, rockfall\n• Human intervention — coastal defences, groynes\n• Climate change — sea level rise, storm frequency\n• Specific rates of retreat at named location\n• Seasonal variation in erosion rates\n• Interaction between factors' },
      { q: 'Explain how an understanding of coastal systems can inform management decisions.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation linking systems understanding to management with specific examples.\nLevel 2 (4-6 marks): Some links between understanding and management.\nLevel 1 (1-3 marks): Basic points with limited linkage.\n\nIndicative content:\n• Systems approach: inputs, outputs, stores, transfers\n• Sediment cells help plan management at appropriate scale\n• Understanding sediment budgets prevents unintended consequences\n• Knowledge of longshore drift direction informs groyne placement\n• Wave energy data guides choice of defence type\n• Geological understanding predicts erosion vulnerability\n• Coastal monitoring provides data for management decisions\n• Shoreline Management Plans based on systems understanding\n• ICZM (Integrated Coastal Zone Management) as holistic approach\n• Failure to understand systems leads to problems elsewhere\n• Cost-benefit analysis informed by process understanding' },
      { q: 'Assess the relative importance of marine and sub-aerial processes in shaping a named stretch of coastline.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed, balanced assessment of both types of process at a named coastline with evaluative conclusion.\nLevel 2 (4-6 marks): Some valid points about both process types.\nLevel 1 (1-3 marks): Basic identification of processes.\n\nIndicative content:\n• Named coastline e.g. Dorset Jurassic Coast, Holderness\n• Marine processes: hydraulic action, abrasion, attrition, wave quarrying\n• Sub-aerial processes: weathering (freeze-thaw, chemical, biological)\n• Mass movement: rockfall, rotational slumping, mudflows\n• Runoff and groundwater seepage weakening cliffs\n• Relative importance depends on geology, climate, exposure\n• Marine processes dominant on exposed, high-energy coasts\n• Sub-aerial processes more important on sheltered coasts with weak geology\n• Both interact — marine erosion undercuts, sub-aerial processes cause collapse\n• Seasonal variation in relative importance\n• Assessment of which is more significant at named location' },

      // 12-20 mark questions (5)
      { q: 'Evaluate the view that coastal management should prioritise the protection of human activity over natural processes.', marks: 20, markScheme: 'Level 4 (16-20 marks): Balanced, evaluative discussion with detailed case study knowledge. Sophisticated understanding of the tension between protection and natural processes. Well-reasoned conclusion.\nLevel 3 (11-15 marks): Good evaluation with relevant examples and developed arguments.\nLevel 2 (6-10 marks): Some relevant points with limited evaluation.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Arguments for prioritising human activity: protection of homes, businesses, infrastructure; economic value of coastal settlements; heritage and cultural value; tourism revenue\n• Arguments for natural processes: sustainability, habitat creation, natural flood defence, sediment supply maintenance\n• Case studies of both approaches (e.g. Holderness, Medmerry)\n• Cost-benefit analysis of protection vs retreat\n• Shoreline Management Plans — hold the line vs managed retreat\n• ICZM principles — balancing economic, social and environmental needs\n• Different stakeholder perspectives\n• Long-term sustainability vs short-term protection\n• Climate change making protection increasingly expensive\n• Ecosystem services provided by natural coastal environments\n• Political and ethical dimensions of the debate\n• Evaluation of whether the dichotomy is valid — can we do both?' },
      { q: 'To what extent do coastal landscapes reflect the balance between erosional and depositional processes?', marks: 20, markScheme: 'Level 4 (16-20 marks): Comprehensive discussion with detailed examples of how both erosion and deposition shape landscapes. Evaluative conclusion about the extent of balance.\nLevel 3 (11-15 marks): Good coverage of both types of processes and resulting landforms.\nLevel 2 (6-10 marks): Some relevant points about erosion and/or deposition.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Erosional landforms: cliffs, wave-cut platforms, caves, arches, stacks, stumps\n• Depositional landforms: beaches, spits, bars, tombolos, sand dunes, salt marshes\n• How wave energy determines dominant process\n• Sediment budget as a measure of balance\n• High-energy coasts dominated by erosion, low-energy by deposition\n• Same coastline has both erosional and depositional zones\n• Temporal changes — storms vs calm conditions shift the balance\n• Longshore drift connects erosional and depositional areas\n• Human intervention affects the balance (e.g. groynes, sea walls)\n• Sea level change affects the balance over longer timescales\n• Dynamic equilibrium concept\n• Named examples of contrasting coastal landscapes\n• Other factors: geology, climate, vegetation, human activity\n• Conclusion assessing the extent to which balance explains landscapes' },
      { q: '"Coastal management is a short-term fix that creates more problems than it solves." Discuss this statement using named examples.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough discussion using multiple named examples with clear evaluation of the statement. Balanced consideration of different management approaches.\nLevel 3 (11-15 marks): Good discussion with some named examples.\nLevel 2 (6-10 marks): Some relevant points with limited examples.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Hard engineering examples: Mappleton — protected but erosion accelerated south; sea walls at Scarborough; groynes at various locations\n• Problems created: sediment starvation downdrift, coastal squeeze, terminal groyne problem\n• High cost of maintenance and replacement\n• Soft engineering as more sustainable alternative\n• Managed retreat examples: Medmerry, Wallasea Island\n• SMP categories and their rationale\n• Some management is effective and necessary (e.g. Thames Barrier)\n• Without management, significant economic and social losses\n• Climate change makes management decisions more difficult\n• ICZM as more holistic and potentially sustainable approach\n• Balance between doing nothing, holding the line, and managed retreat\n• Different perspectives: local residents, planners, environmentalists\n• Conclusion evaluating the validity of the statement' },
      { q: 'Discuss the factors that influence the development of coastal landscapes at contrasting locations.', marks: 20, markScheme: 'Level 4 (16-20 marks): Detailed discussion of multiple factors using contrasting locations with clear analysis of how factors interact.\nLevel 3 (11-15 marks): Good coverage of factors at different locations.\nLevel 2 (6-10 marks): Some factors identified with limited contrast.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Geology: rock type, structure, dip, faults, joints\n• Wave energy and climate: fetch, wind patterns, storm frequency\n• Tidal range: micro-tidal vs macro-tidal environments\n• Sediment supply and type\n• Sea level change: eustatic and isostatic\n• Sub-aerial processes: weathering, mass movement, vegetation\n• Human activity: management, development, resource extraction\n• Contrasting examples (e.g. Dorset vs Holderness, coral coast vs rocky coast)\n• How factors interact at each location\n• Timescales of landscape development\n• Climate change as emerging factor\n• Relative importance of factors varies between locations\n• Systems approach to understanding landscape development' },
      { q: 'Evaluate the extent to which coastal systems can be considered to be in a state of dynamic equilibrium.', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated evaluation of dynamic equilibrium concept applied to coastal systems with detailed examples and nuanced conclusion.\nLevel 3 (11-15 marks): Good understanding of equilibrium concept with relevant examples.\nLevel 2 (6-10 marks): Some understanding with limited application.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Definition: dynamic equilibrium means the system adjusts to maintain a state of balance\n• Negative feedback: cliff erosion supplies beach sediment which then protects the cliff\n• Seasonal adjustments: summer berms and winter storm profiles\n• Sediment budgets balance inputs and outputs\n• Evidence for equilibrium: beaches adjust profile to wave conditions\n• Factors that disrupt equilibrium: storms, sea level rise, human intervention\n• Positive feedback can push system away from equilibrium\n• Human activity often disrupts natural equilibrium (groynes, sea walls)\n• Climate change as long-term disruption to equilibrium\n• Recovery time after disturbance events\n• Scale — equilibrium may exist at large scale but not locally\n• Timescale — short-term disruption vs long-term adjustment\n• Named examples showing equilibrium and disequilibrium\n• Conclusion on the extent to which equilibrium applies' },
    ],
  },
  '1.3': {
    name: 'Hazards',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two primary hazards associated with volcanic eruptions.', marks: 2, markScheme: '• Lava flows (1)\n• Pyroclastic flows / tephra / volcanic gases / lahars (1)' },
      { q: 'Define the term "hazard risk".', marks: 2, markScheme: '• The probability/likelihood of a hazard event occurring (1)\n• And causing loss of life, injury, or damage / affecting a vulnerable population (1)' },
      { q: 'State three factors that affect vulnerability to tectonic hazards.', marks: 3, markScheme: '• Level of economic development / wealth (1)\n• Population density near hazard zone (1)\n• Quality of infrastructure / building standards / preparedness / governance (1)' },
      { q: 'Define the term "disaster".', marks: 2, markScheme: '• A hazard event that causes significant damage / disruption / loss of life (1)\n• That overwhelms the affected community\'s ability to cope using its own resources (1)' },
      { q: 'State two differences between a shield volcano and a composite (stratovolcano).', marks: 2, markScheme: '• Shield volcanoes have gentle slopes / composite have steep, cone-shaped profiles (1)\n• Shield volcanoes produce basaltic/low viscosity lava / composite produce andesitic/high viscosity lava and explosive eruptions (1)' },
      { q: 'Define the term "liquefaction" in the context of earthquake hazards.', marks: 2, markScheme: '• When waterlogged/saturated soil or sediment loses strength during earthquake shaking (1)\n• And behaves like a liquid, causing buildings/structures to sink or collapse (1)' },
      { q: 'State two ways in which tropical storms can be monitored.', marks: 2, markScheme: '• Satellite imagery / remote sensing (1)\n• Weather stations / aircraft reconnaissance / ocean buoys / radar (1)' },
      { q: 'Define the term "hotspot" in the context of plate tectonics.', marks: 3, markScheme: '• A localised area of intense volcanic activity (1)\n• Caused by a rising plume of hot mantle material (1)\n• That is not associated with a plate boundary / occurs within a tectonic plate (1)' },
      { q: 'State two characteristics of a tropical storm.', marks: 2, markScheme: '• Low pressure system with sustained winds of 119+ km/h / 74+ mph (1)\n• Formed over warm tropical oceans (26.5°C+) / has an eye, eyewall, and spiral rainbands (1)' },
      { q: 'Define the term "resilience" in the context of natural hazards.', marks: 2, markScheme: '• The ability of a community/society to recover from (1)\n• And adapt to the impacts of a hazard event (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain the distribution of earthquakes and volcanic activity at constructive (divergent) plate boundaries.', marks: 6, markScheme: '• Plates move apart due to convection currents in the mantle (1)\n• Magma rises to fill the gap between diverging plates (1)\n• Creates new oceanic crust — seafloor spreading (1)\n• Volcanic activity is typically effusive with basaltic lava (1)\n• Earthquakes are generally shallow and low magnitude (1)\n• Example: Mid-Atlantic Ridge / East African Rift (1)\n• Rift valleys form on continental divergent boundaries (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the formation and characteristics of a tropical storm.', marks: 6, markScheme: '• Forms over warm ocean water (26.5°C+ to depth of 60-70m) (1)\n• Warm, moist air rises rapidly, creating low pressure (1)\n• Coriolis effect causes rotation of the storm system (1)\n• Latent heat released by condensation fuels the storm (1)\n• Eye forms at the centre — calm, descending air (1)\n• Eyewall contains the most intense winds and rainfall (1)\n• Spiral rainbands extend outward from the centre (1)\n• Weakens over land or cold water as energy source removed (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain why the impacts of earthquakes differ between high-income countries (HICs) and low-income countries (LICs).', marks: 6, markScheme: '• HICs have stricter building codes — earthquake-resistant design (1)\n• HICs have better emergency services and healthcare infrastructure (1)\n• LICs have higher population density in vulnerable areas (1)\n• LICs lack financial resources for preparedness and response (1)\n• HICs have better communication and warning systems (1)\n• LICs have higher death tolls but HICs have higher economic losses (1)\n• Education and awareness programmes better funded in HICs (1)\n• Insurance availability differs significantly (1)\n• Credit any valid comparative points, max 6 marks' },
      { q: 'Describe the hazards associated with a named volcanic eruption you have studied.', marks: 6, markScheme: '• Named volcanic eruption e.g. Mount Pinatubo 1991, Eyjafjallajokull 2010 (1)\n• Primary hazards: lava flows, pyroclastic flows, tephra/ash fall (1 per hazard)\n• Secondary hazards: lahars, tsunamis, flooding, gas emissions (1 per hazard)\n• Specific details of the named eruption (1)\n• Scale/extent of hazards described (1)\n• Credit specific data/facts about the named event\n• Max 6 marks' },
      { q: 'Draw and label a cross-section diagram showing the features of a destructive plate boundary.', marks: 5, diagram: true, markScheme: '• Oceanic plate shown subducting beneath continental plate (1)\n• Subduction zone / Benioff zone labelled (1)\n• Ocean trench shown at the boundary (1)\n• Volcanic arc/mountains shown on continental plate (1)\n• Magma rising from melting oceanic plate shown (1)\n• Earthquake foci shown at increasing depth along subduction zone (1)\n• Credit any valid additional labels, max 5 marks' },
      { q: 'Explain how communities can prepare for and mitigate the impacts of tropical storms.', marks: 6, markScheme: '• Early warning systems using satellite monitoring (1)\n• Evacuation plans and designated shelters (1)\n• Building codes — reinforced structures, raised foundations (1)\n• Flood defences — sea walls, levees, storm surge barriers (1)\n• Community education and preparedness drills (1)\n• Land use planning — restricting development in vulnerable areas (1)\n• Insurance and emergency supplies (1)\n• International aid coordination (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the concept of the hazard risk equation.', marks: 4, markScheme: '• Risk = Hazard × Vulnerability / Capacity (to cope) (1)\n• Hazard: the physical event — magnitude, frequency, duration (1)\n• Vulnerability: characteristics that make a population susceptible (1)\n• Capacity: the ability to prepare for, respond to and recover from hazards (1)\n• Risk increases when vulnerability is high and capacity is low (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain how earthquake waves cause damage to structures and infrastructure.', marks: 5, markScheme: '• P-waves (primary) travel fastest — compress and expand rock (1)\n• S-waves (secondary) cause shaking — side-to-side movement (1)\n• Surface waves cause most damage — rolling/ground motion (1)\n• Shaking causes buildings to collapse, especially unreinforced structures (1)\n• Liquefaction causes foundations to fail in waterlogged sediment (1)\n• Landslides triggered on steep slopes (1)\n• Infrastructure damage: roads, bridges, pipelines, utilities (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain how volcanic eruptions can have global climatic impacts.', marks: 4, markScheme: '• Large eruptions inject SO2 and ash into the stratosphere (1)\n• Sulphur dioxide forms sulphate aerosols that reflect solar radiation (1)\n• This reduces global temperatures — volcanic winter (1)\n• Example: Pinatubo 1991 reduced global temps by ~0.5°C for 1-2 years (1)\n• Ash can disrupt air travel over wide areas (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain why people continue to live in areas at risk from tectonic hazards.', marks: 6, markScheme: '• Fertile volcanic soils support agriculture (1)\n• Geothermal energy provides cheap power (1)\n• Tourism and employment opportunities (1)\n• Perception that the risk is low / infrequent events (1)\n• Economic factors — cannot afford to move / livelihoods tied to area (1)\n• Cultural and family ties to the area (1)\n• Lack of awareness of the risk (1)\n• Government policies / lack of alternative housing options (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Describe the evidence used to support the theory of plate tectonics.', marks: 6, markScheme: '• Continental fit — coastlines of South America and Africa (1)\n• Fossil evidence — similar fossils found on now-separated continents (1)\n• Rock and geological evidence — matching rock types and mountain chains (1)\n• Palaeomagnetic evidence — magnetic striping on ocean floor (1)\n• Seafloor spreading evidence from ocean drilling (1)\n• Distribution of earthquakes and volcanoes along plate boundaries (1)\n• GPS measurement of plate movement (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the hazards associated with a named tropical storm event.', marks: 5, markScheme: '• Named event e.g. Hurricane Katrina 2005, Typhoon Haiyan 2013 (1)\n• High winds causing structural damage (1)\n• Storm surge causing coastal flooding (1)\n• Intense rainfall causing river flooding and landslides (1)\n• Specific impacts at the named location (1)\n• Scale/magnitude of the event (1)\n• Credit specific data from the named event, max 5 marks' },
      { q: 'Explain the role of convection currents in driving plate movement.', marks: 4, markScheme: '• Radioactive decay generates heat in the Earth\'s core and mantle (1)\n• Hot mantle material rises towards the crust (1)\n• At the surface it spreads laterally, dragging plates apart (1)\n• Cooled material sinks back down, creating convection cells (1)\n• Ridge push and slab pull also contribute to plate movement (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Describe the Park model of human response to hazards.', marks: 4, markScheme: '• Shows the stages of response over time after a hazard event (1)\n• Begins with the hazard event causing a drop in quality of life/normality (1)\n• Relief/rescue stage — immediate response and emergency aid (1)\n• Rehabilitation stage — restoring services and infrastructure (1)\n• Reconstruction stage — rebuilding, may reach higher level than before (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain the difference between conservative and destructive plate boundaries.', marks: 4, markScheme: '• At conservative boundaries, plates slide past each other (1)\n• No crust is created or destroyed — no volcanic activity (1)\n• At destructive boundaries, plates converge/collide (1)\n• Oceanic plate subducts, creating volcanic activity and deep earthquakes (1)\n• Example: San Andreas (conservative) vs Pacific Ring of Fire (destructive) (1)\n• Credit any valid points, max 4 marks' },

      // 8-9 mark questions (10)
      { q: 'Assess the extent to which the impacts of tectonic hazards can be reduced through management strategies.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple strategies with evaluation of their effectiveness, using named examples.\nLevel 2 (4-6 marks): Some strategies discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of strategies.\n\nIndicative content:\n• Prediction and monitoring: seismometers, GPS, gas emissions\n• Early warning systems for tsunamis\n• Building design: earthquake-resistant structures, base isolation\n• Land use planning: avoiding high-risk zones\n• Education and preparedness programmes\n• Emergency response planning and drills\n• International aid and disaster relief coordination\n• Limitations: earthquakes cannot be predicted accurately\n• Effectiveness varies between HICs and LICs\n• Named examples of successful and unsuccessful management\n• Assessment of which strategies are most effective' },
      { q: 'Explain why some tectonic hazards have greater impacts than others.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of multiple factors with named examples and clear analysis.\nLevel 2 (4-6 marks): Some factors explained with partial development.\nLevel 1 (1-3 marks): Basic identification of factors.\n\nIndicative content:\n• Magnitude/intensity of the event\n• Depth and location (shallow, near populated areas = more damage)\n• Population density and distribution\n• Level of economic development\n• Building standards and infrastructure quality\n• Preparedness and warning systems\n• Time of day and season\n• Secondary hazards (tsunami, landslides, fires)\n• Capacity to respond and recover\n• Named examples showing contrasting impacts\n• e.g. Haiti 2010 vs Japan 2011 or Chile 2010' },
      { q: 'Assess the extent to which climate change may affect the frequency and intensity of tropical storms.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed, nuanced assessment of the relationship between climate change and tropical storms with reference to evidence.\nLevel 2 (4-6 marks): Some valid points about the relationship.\nLevel 1 (1-3 marks): Basic points with limited development.\n\nIndicative content:\n• Warmer ocean temperatures provide more energy for storm formation\n• Potential for more intense storms with higher wind speeds\n• More moisture in atmosphere → more intense rainfall\n• Rising sea levels increase storm surge risk\n• However, frequency may not increase — may actually decrease\n• Wind shear changes could suppress storm formation in some areas\n• Evidence from recent decades: more Category 4-5 storms\n• Scientific debate about attribution of individual storms\n• Expansion of tropical storm formation zones poleward\n• Assessment of certainty of predictions\n• IPCC projections and limitations of climate models' },
      { q: 'Explain the role of governance in managing the impacts of natural hazards, using named examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with named examples showing how governance affects hazard management and outcomes.\nLevel 2 (4-6 marks): Some valid points about governance with examples.\nLevel 1 (1-3 marks): Basic points with limited development.\n\nIndicative content:\n• Government investment in monitoring and early warning\n• Building regulations and enforcement\n• Land use planning and zoning laws\n• Emergency response planning and coordination\n• Education and public awareness campaigns\n• International cooperation and aid agreements\n• Good governance: Japan — strict building codes, regular drills\n• Poor governance: Haiti — corruption, lack of building standards\n• Political will and prioritisation of hazard management\n• Role of NGOs and international organisations where governance is weak\n• Corruption can divert resources from hazard management' },
      { q: 'Assess the view that earthquakes are always more destructive than volcanic eruptions.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment with named examples of both types, reaching an evaluative conclusion.\nLevel 2 (4-6 marks): Some comparison with partial assessment.\nLevel 1 (1-3 marks): Basic points about earthquakes and/or volcanoes.\n\nIndicative content:\n• Earthquakes: sudden onset, widespread shaking, tsunamis\n• High death tolls: Haiti 2010 (316,000+), Indian Ocean 2004\n• Cannot be predicted — no evacuation possible\n• Volcanic eruptions: can often be monitored and predicted\n• But catastrophic eruptions can be extremely destructive (Pinatubo, Tambora)\n• Pyroclastic flows are nearly impossible to survive\n• Volcanoes have long-term climatic impacts\n• Context matters: location, population, development level\n• Not always — small earthquakes vs large eruptions\n• Assessment should consider frequency, magnitude, vulnerability\n• Conclusion: depends on the specific event and context' },
      { q: 'Explain the causes and impacts of a tsunami, with reference to a named event.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of causes and impacts with specific detail from named event.\nLevel 2 (4-6 marks): Some valid points about causes and/or impacts.\nLevel 1 (1-3 marks): Basic points with limited detail.\n\nIndicative content:\n• Caused by displacement of large volume of ocean water\n• Usually triggered by submarine earthquake at destructive boundary\n• Also: volcanic eruptions, underwater landslides\n• Waves travel at high speed across ocean (up to 800 km/h)\n• Wave height increases dramatically in shallow coastal water\n• Named event e.g. Indian Ocean 2004, Japan 2011\n• Devastating coastal flooding and destruction\n• Massive loss of life — 230,000+ in Indian Ocean tsunami\n• Infrastructure destruction — buildings, roads, ports\n• Environmental damage — saltwater intrusion, habitat destruction\n• Long-term economic and social impacts\n• Secondary hazards: disease, water contamination' },
      { q: 'Explain how multi-hazard environments present particular challenges for communities.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of challenges in multi-hazard contexts with named examples.\nLevel 2 (4-6 marks): Some valid points about multi-hazard challenges.\nLevel 1 (1-3 marks): Basic identification of challenges.\n\nIndicative content:\n• Multiple hazard types require different preparation strategies\n• Resource allocation challenges — which hazard to prioritise\n• Compound events can overwhelm response capacity\n• Philippines: typhoons, earthquakes, volcanic eruptions, flooding\n• Japan: earthquakes, tsunamis, volcanic eruptions, typhoons\n• Cascading hazards — earthquake triggers tsunami triggers nuclear disaster\n• Fatigue — frequent events reduce preparedness\n• Economic burden of preparing for multiple hazards\n• Insurance and risk assessment complexity\n• However: experience builds resilience and institutional knowledge\n• International support may be needed for multi-hazard regions' },
      { q: 'Assess the effectiveness of technology in reducing the impacts of natural hazards.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple technologies with evaluation of their effectiveness, using examples.\nLevel 2 (4-6 marks): Some technologies discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of technologies.\n\nIndicative content:\n• Seismometers and GPS for earthquake monitoring\n• Satellite imagery for tracking tropical storms\n• Tsunami warning systems (buoys, tide gauges)\n• Volcanic monitoring (tiltmeters, gas analysis, thermal imaging)\n• GIS for hazard mapping and risk assessment\n• Communication technology for warnings and evacuation\n• Building technology: base isolation, cross-bracing\n• Remote sensing for post-disaster damage assessment\n• Limitations: earthquakes remain unpredictable\n• Technology alone insufficient without governance and education\n• Access to technology varies between HICs and LICs\n• Assessment of which technologies have been most effective' },
      { q: 'Explain how the perception of hazard risk varies between different groups of people.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of how and why perceptions differ between groups with examples.\nLevel 2 (4-6 marks): Some valid points about varying perceptions.\nLevel 1 (1-3 marks): Basic points about risk perception.\n\nIndicative content:\n• Fatalism — acceptance that hazards are beyond human control (common in LICs)\n• Adaptation — belief that the environment can be modified to reduce risk\n• Fear/concern — anxiety about potential impacts\n• Optimism bias — "it won\'t happen to me"\n• Experience of past events increases or decreases perceived risk\n• Age, education, and income affect perception\n• Cultural and religious beliefs influence perception\n• Distance from hazard zone affects perceived risk\n• Media coverage can amplify or reduce risk perception\n• Government and expert communication influence public perception\n• Economic dependence on hazardous area affects willingness to accept risk' },
      { q: 'Assess the extent to which the location and timing of hazard events determine their impacts.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of both location and timing factors with named examples and evaluative conclusion.\nLevel 2 (4-6 marks): Some consideration of location and/or timing.\nLevel 1 (1-3 marks): Basic points with limited assessment.\n\nIndicative content:\nLocation factors:\n• Proximity to populated areas\n• Urban vs rural location\n• Proximity to coast (tsunami risk)\n• Geology and soil type (liquefaction, landslide risk)\n• Level of development of affected area\nTiming factors:\n• Time of day (daytime vs nighttime — evacuation possibilities)\n• Season (wet season increases flood/lahar risk)\n• Time since last event (preparedness fatigue or heightened awareness)\n• Rapid onset vs slow onset events\nNamed examples showing how location/timing affected impacts\nOther factors: magnitude, governance, preparedness\nAssessment of relative importance of location vs timing vs other factors' },

      // 12-20 mark questions (5)
      { q: 'Evaluate the extent to which it is possible to mitigate the effects of tectonic hazards. Use named examples in your answer.', marks: 20, markScheme: 'Level 4 (16-20 marks): Detailed, evaluative response with multiple named examples showing both successes and limitations of mitigation. Well-structured argument with nuanced conclusion.\nLevel 3 (11-15 marks): Good evaluation with named examples and developed discussion.\nLevel 2 (6-10 marks): Some relevant points about mitigation with limited evaluation.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Prediction: volcanic eruptions more predictable than earthquakes\n• Monitoring technologies and their effectiveness\n• Building design: Japan vs Haiti comparison\n• Land use planning: exclusion zones around volcanoes\n• Early warning systems: Pacific Tsunami Warning Centre\n• Emergency preparedness: drills, education, response plans\n• Named examples: Japan 2011 — high preparedness but still devastating\n• Nepal 2015 — limited capacity to mitigate\n• Iceland — effective volcanic monitoring and response\n• Chile — improved building codes after historic earthquakes\n• Limitations: earthquakes remain unpredictable\n• Economic constraints in LICs\n• Mega-events overwhelm any preparation\n• Role of international aid in mitigation\n• Assessment of what is achievable vs aspirational\n• Conclusion on extent of mitigation possible' },
      { q: 'To what extent does the level of economic development determine the severity of hazard impacts? Refer to named examples in your answer.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough evaluation of the relationship between development and hazard impacts using multiple named examples. Balanced consideration of other factors. Nuanced conclusion.\nLevel 3 (11-15 marks): Good discussion with named examples and some evaluation.\nLevel 2 (6-10 marks): Some relevant points with limited named examples.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• HICs: better building standards, emergency services, infrastructure\n• LICs: higher death tolls due to poor infrastructure and limited resources\n• HICs: higher absolute economic losses but greater capacity to recover\n• LICs: economic losses represent higher proportion of GDP\n• Named HIC example: Japan 2011 — advanced preparation but still 18,000+ deaths\n• Named LIC example: Haiti 2010 — 316,000+ deaths, collapsed infrastructure\n• However: magnitude and location also critical factors\n• Governance and corruption independent of GDP\n• Community resilience and social capital\n• Chile 2010 vs Haiti 2010 — similar magnitude, different outcomes\n• Other factors: population density, hazard type, time of day\n• Development is important but not the only factor\n• Conclusion assessing the extent to which development determines impacts' },
      { q: '"Tropical storms are the most dangerous natural hazard." Discuss this statement with reference to named examples.', marks: 20, markScheme: 'Level 4 (16-20 marks): Balanced, well-evidenced discussion comparing tropical storms with other hazard types. Multiple named examples with evaluative conclusion.\nLevel 3 (11-15 marks): Good discussion with some comparison and named examples.\nLevel 2 (6-10 marks): Some relevant points about tropical storms and/or other hazards.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Tropical storms: high winds, flooding, storm surge — Typhoon Haiyan 2013 (6,300+ deaths), Hurricane Katrina 2005\n• Can be predicted and tracked — time for evacuation\n• Wide area of impact but relatively slow onset\n• Earthquakes: sudden onset, cannot be predicted — Haiti 2010, Nepal 2015\n• Tsunamis: devastating but localised to coasts — 2004 Indian Ocean\n• Volcanic eruptions: severe but often predictable — Pinatubo 1991\n• Floods: most common natural hazard globally\n• Drought: slow onset but massive long-term impacts — famine, displacement\n• "Most dangerous" depends on definition: deaths, economic loss, area affected\n• Frequency vs severity debate\n• Climate change may intensify tropical storms\n• Context and vulnerability determine danger more than hazard type\n• Conclusion: no single hazard is universally "most dangerous"' },
      { q: 'Discuss the view that natural hazard events are becoming more frequent and severe due to human activity.', marks: 20, markScheme: 'Level 4 (16-20 marks): Comprehensive, evaluative discussion considering multiple types of hazard and the role of human activity. Well-evidenced with nuanced conclusion.\nLevel 3 (11-15 marks): Good discussion with some evaluation and evidence.\nLevel 2 (6-10 marks): Some relevant points with limited evaluation.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Climate change: increasing intensity of tropical storms, floods, droughts\n• Deforestation increases flood and landslide risk\n• Urbanisation increases vulnerability and exposure\n• Population growth in hazard-prone areas\n• Land use change (e.g. floodplain development)\n• However: tectonic hazards not influenced by human activity\n• Better monitoring means more events recorded — reporting bias\n• Increased losses may reflect population growth, not more events\n• Evidence: IPCC data on extreme weather events\n• Fracking linked to induced seismicity\n• Reservoir-induced seismicity\n• Distinction between natural frequency and human-modified risk\n• Assessment of which hazard types are genuinely increasing\n• Role of vulnerability in determining whether events become disasters\n• Conclusion considering evidence for and against the statement' },
      { q: 'Evaluate the importance of international cooperation in managing the impacts of natural hazards. Use named examples to support your answer.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough evaluation with multiple named examples showing successes and limitations of international cooperation. Balanced, well-reasoned conclusion.\nLevel 3 (11-15 marks): Good evaluation with named examples.\nLevel 2 (6-10 marks): Some relevant points with limited evaluation.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• UN frameworks: Sendai Framework for Disaster Risk Reduction\n• International aid: humanitarian response to major disasters\n• Technology sharing: tsunami warning systems across Pacific\n• Named examples of effective international response\n• Named examples of inadequate or slow international response\n• NGOs and their role in disaster response and preparedness\n• Climate change agreements (Paris) to reduce future hazard risk\n• Financial assistance: World Bank, disaster relief funds\n• Scientific cooperation: monitoring, research, data sharing\n• However: sovereignty issues limit external intervention\n• Political factors affect aid distribution\n• Dependency culture vs building local capacity\n• Coordination challenges between agencies\n• Assessment of whether international cooperation is sufficient\n• Comparison of hazard management in isolated vs well-connected nations' },
    ],
  },
  '2.1': {
    name: 'Changing Places',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two ways in which a person\'s experience of a place can differ from that of another person.', marks: 2, markScheme: '• Age — children vs adults experience place differently (1)\n• Socioeconomic status — wealth affects access to and experience of places (1)\n• Or: gender, ethnicity, cultural background, length of residency, emotional attachment (1)' },
      { q: 'Define the term "sense of place".', marks: 2, markScheme: '• The subjective and emotional attachment people feel towards a place (1)\n• Based on their personal experiences, memories, and meanings associated with it (1)' },
      { q: 'State two factors that influence a place\'s identity.', marks: 2, markScheme: '• Physical characteristics — landscape, climate, natural features (1)\n• Human characteristics — buildings, culture, demographics, economic activity (1)' },
      { q: 'Define the term "placelessness".', marks: 2, markScheme: '• The loss of unique character/identity of a place (1)\n• Often through standardisation/globalisation making places look and feel the same (1)' },
      { q: 'State two types of quantitative data that could be used to investigate the characteristics of a place.', marks: 2, markScheme: '• Census data — population, ethnicity, age structure (1)\n• Economic data — employment statistics, house prices, income levels (1)' },
      { q: 'Define the term "insider perspective" in relation to place.', marks: 3, markScheme: '• The experience and understanding of a place (1)\n• Held by people who live in or belong to that place (1)\n• Based on daily lived experience and personal attachment (1)' },
      { q: 'State two ways in which globalisation can change the character of a place.', marks: 2, markScheme: '• Introduction of global brands/chain stores replacing local businesses (1)\n• Migration bringing cultural diversity / changing demographics (1)' },
      { q: 'Define the term "representation" in relation to place.', marks: 2, markScheme: '• How a place is portrayed/depicted to others (1)\n• Through media, art, literature, photography, maps, or other forms (1)' },
      { q: 'State two differences between near and far places in terms of how we experience them.', marks: 2, markScheme: '• Near places are experienced directly through lived experience / everyday interaction (1)\n• Far places are experienced indirectly through media, accounts of others, representations (1)' },
      { q: 'Define the term "place profile".', marks: 3, markScheme: '• A description or summary of the key characteristics of a place (1)\n• Including physical, human, demographic, cultural, and economic features (1)\n• Often using a combination of quantitative and qualitative data (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain how personal experiences can shape an individual\'s perception of a place.', marks: 6, markScheme: '• Childhood memories create strong emotional attachments to places (1)\n• Positive experiences (celebrations, friendships) create topophilia / sense of belonging (1)\n• Negative experiences (crime, discrimination) create topophobia / avoidance (1)\n• Length of residence affects depth of attachment (1)\n• Familiarity breeds comfort and positive perception (1)\n• Significant life events at a place create lasting associations (1)\n• Sensory experiences (sounds, smells) trigger place memories (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain how the media can influence perceptions of a place.', marks: 6, markScheme: '• News coverage can create positive or negative images of a place (1)\n• Selective reporting may emphasise crime, poverty, or social problems (1)\n• Film and television can romanticise or stigmatise places (1)\n• Social media shares curated images influencing perceptions (1)\n• Advertising and tourism marketing create aspirational images (1)\n• Literature and art represent places in particular ways (1)\n• Place branding and rebranding efforts use media strategically (1)\n• These representations may not reflect lived reality (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain how demographic change can alter the character of a place.', marks: 6, markScheme: '• In-migration introduces new cultures, languages, and traditions (1)\n• Ageing population changes demand for services (1)\n• Young people leaving can lead to rural decline (1)\n• Gentrification brings wealthier residents and changes local services (1)\n• Student populations create distinct cultural economies (1)\n• Counter-urbanisation changes rural village character (1)\n• Ethnic diversity changes food, shops, and cultural landscape (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the difference between quantitative and qualitative approaches to investigating place.', marks: 4, markScheme: '• Quantitative uses numerical/statistical data (1)\n• E.g. census data, employment figures, house prices (1)\n• Qualitative uses subjective/descriptive data (1)\n• E.g. interviews, photographs, personal accounts, diary entries (1)\n• Quantitative provides objective overview; qualitative provides depth and meaning (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain how economic change can transform the identity of a place.', marks: 6, markScheme: '• Deindustrialisation changes the economic base and employment structure (1)\n• Factory closures alter the physical landscape — derelict buildings (1)\n• New economic activities (service sector, technology) attract different populations (1)\n• Gentrification changes the social and economic character (1)\n• Tourism development can rebrand a place\'s identity (1)\n• Decline of primary industry changes rural place identities (1)\n• Investment and regeneration can create new place narratives (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain how the physical environment influences the character of places.', marks: 5, markScheme: '• Relief and topography affect settlement patterns and land use (1)\n• Climate influences economic activity (agriculture, tourism) (1)\n• Coastal locations develop distinctive characters linked to the sea (1)\n• Rivers create settlement sites and influence urban form (1)\n• Natural hazard risk shapes building design and community resilience (1)\n• Geology and soil affect vegetation and agricultural character (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain why different people may have different lived experiences of the same place.', marks: 6, markScheme: '• Age affects mobility, activities, and social networks in a place (1)\n• Gender may influence feelings of safety and access to spaces (1)\n• Ethnicity and cultural background shape social interactions (1)\n• Socioeconomic status affects access to services and opportunities (1)\n• Disability affects physical access and inclusion (1)\n• Insider vs outsider status affects sense of belonging (1)\n• Time of day changes the experience of a place (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain how past and present connections to other places shape a place\'s character.', marks: 5, markScheme: '• Colonial connections influence architecture, culture, and demographics (1)\n• Trade links shape economic character and employment (1)\n• Migration flows bring cultural diversity and new traditions (1)\n• Transport connections determine accessibility and commuter patterns (1)\n• Digital connections enable remote working and global cultural exchange (1)\n• Historical connections create heritage and tourism identity (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Describe how regeneration and rebranding can change people\'s perception of a place.', marks: 4, markScheme: '• Physical renewal improves the built environment — new buildings, public spaces (1)\n• Marketing campaigns create positive new narratives about the place (1)\n• Cultural investment (galleries, events) attracts positive media attention (1)\n• Improved services and employment opportunities change perceived desirability (1)\n• However, existing residents may resist or feel excluded from changes (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain the concept of a "place meaning" and how it can change over time.', marks: 4, markScheme: '• Place meaning refers to the significance/value attached to a place by individuals or groups (1)\n• Meanings are socially constructed and can be contested (1)\n• Historical events can permanently alter a place\'s meaning (1)\n• Regeneration and investment can transform meanings from negative to positive (1)\n• Different groups may attach different meanings simultaneously (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain how government policies can change the character of places.', marks: 6, markScheme: '• Planning policy determines what is built and where (1)\n• Housing policy influences social composition (e.g. social housing, right to buy) (1)\n• Transport investment changes connectivity and accessibility (1)\n• Enterprise zones and regeneration grants attract economic activity (1)\n• Conservation designations protect heritage character (1)\n• Austerity measures / public service cuts affect local facilities (1)\n• Immigration policy affects demographic character (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the concept of topophilia and how it develops.', marks: 4, markScheme: '• Topophilia is a strong sense of love for or attachment to a place (1)\n• Develops through positive experiences and memories (1)\n• Long-term residence and familiarity deepen attachment (1)\n• Aesthetic appreciation of landscape or built environment (1)\n• Cultural and social ties bind people to places (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Describe how the identity of a named place has changed over time.', marks: 6, markScheme: '• Named place with specific detail about past character (1)\n• Description of key changes (economic, social, cultural, physical) (1 per valid change)\n• Factors driving the change explained (1)\n• Evidence of how identity has shifted (1)\n• May include reference to how the place is perceived now vs in the past (1)\n• Credit specific detail from named place, max 6 marks' },
      { q: 'Explain how art and literature can represent places in particular ways.', marks: 5, markScheme: '• Artists select particular features to emphasise in their work (1)\n• Literary descriptions create imaginative geographies of places (1)\n• Historical paintings show how places appeared and were valued (1)\n• Poetry and novels can romanticise or critique places (1)\n• Photography frames places in selective ways (1)\n• These representations shape wider public perceptions (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain the difference between an insider and outsider perspective on a place.', marks: 4, markScheme: '• Insiders live in/belong to a place and have direct, everyday experience (1)\n• Their perspective is shaped by personal memories and emotional attachment (1)\n• Outsiders experience a place as visitors or through second-hand representations (1)\n• Outsiders may rely on stereotypes, media portrayals, or limited visits (1)\n• Both perspectives are valid but provide different understandings (1)\n• Credit any valid points, max 4 marks' },

      // 8-9 mark questions (10)
      { q: 'Assess the extent to which globalisation has led to placelessness in the modern world.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed, well-developed assessment with named examples, considering both placelessness and enduring uniqueness.\nLevel 2 (4-6 marks): Some valid points with partial assessment.\nLevel 1 (1-3 marks): Basic points about globalisation and place.\n\nIndicative content:\n• Global chains (McDonald\'s, Starbucks) create homogenous commercial landscapes\n• Clone towns — identical high streets\n• Global architectural styles in cities\n• Social media creates standardised cultural experiences\n• However: local cultures actively resist placelessness\n• Heritage conservation preserves unique character\n• Glocalisation — global brands adapt to local contexts\n• Place branding emphasises uniqueness\n• Natural landscapes resist homogenisation\n• Cultural traditions maintain distinctiveness\n• Assessment of the extent — partial but not total placelessness' },
      { q: 'Explain how the character of a named place has been shaped by both internal and external forces.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of a named place with clear analysis of internal and external forces.\nLevel 2 (4-6 marks): Some valid points with reference to a named place.\nLevel 1 (1-3 marks): Basic points with limited reference to a specific place.\n\nIndicative content:\n• Named place with specific characteristics described\n• Internal forces: local decision-making, community action, physical geography, local culture\n• External forces: government policy, globalisation, migration, investment, media\n• Demographic change driven by both internal and external factors\n• Economic restructuring from external forces (globalisation, deindustrialisation)\n• Community response as internal force\n• Interaction between internal and external forces\n• How the balance of forces has changed over time\n• Assessment of which forces have been most significant' },
      { q: 'Assess the role of different agents of change in shaping the character of places.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple agents with evaluation of relative importance.\nLevel 2 (4-6 marks): Some agents discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of agents.\n\nIndicative content:\n• Government: planning policy, investment, regeneration\n• Corporate: business investment, employment, services\n• Community groups: grassroots campaigns, local initiatives\n• Individuals: entrepreneurs, artists, activists\n• Developers: housing, commercial, infrastructure\n• Cultural institutions: museums, universities, arts organisations\n• Media: representation and perception of places\n• Named examples of agents changing specific places\n• Conflict between different agents\n• Assessment of which agents have most influence' },
      { q: 'Explain how and why the lived experience of a place differs for people of different ages and backgrounds.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with specific examples of how experiences differ.\nLevel 2 (4-6 marks): Some valid points about differing experiences.\nLevel 1 (1-3 marks): Basic identification of differences.\n\nIndicative content:\n• Children: limited mobility, experience through play and school\n• Young adults: nightlife, education, social networks\n• Elderly: memories, reduced mobility, access to services\n• Wealthy vs poor: different access to spaces and services\n• Ethnic minorities: may face discrimination or feel excluded\n• Recent migrants vs long-term residents: different attachment levels\n• Gender: different safety perceptions, use of public space\n• Disability: physical access barriers\n• These differences create contested spaces and multiple place identities\n• Power dynamics determine whose experience dominates' },
      { q: 'Assess the extent to which place can be considered a social construction.', marks: 9, markScheme: 'Level 3 (7-9 marks): Sophisticated assessment considering both social construction and physical reality of place.\nLevel 2 (4-6 marks): Some valid points about social construction.\nLevel 1 (1-3 marks): Basic points with limited assessment.\n\nIndicative content:\n• Places are given meaning by human experiences and interactions\n• Different groups construct different meanings for the same place\n• Media representations socially construct place images\n• Place names and boundaries are socially determined\n• Heritage and memory are selectively constructed\n• Place branding deliberately constructs images\n• However: physical geography is real, not constructed\n• Material conditions (housing, infrastructure) are tangible\n• Environmental determinism suggests physical factors shape places\n• Assessment: places have both material and constructed dimensions\n• Power relations determine which constructions become dominant' },
      { q: 'Explain how migration can create both opportunities and tensions within a place.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced explanation of both opportunities and tensions with named examples.\nLevel 2 (4-6 marks): Some valid points about migration impacts.\nLevel 1 (1-3 marks): Basic points about migration.\n\nIndicative content:\nOpportunities:\n• Cultural diversity enriches community life\n• New businesses and economic activity\n• Skills and labour force contributions\n• Vibrant food, music, and cultural scene\n• Demographic rejuvenation in ageing communities\nTensions:\n• Competition for housing, jobs, services\n• Language barriers and communication challenges\n• Cultural misunderstandings or clashes\n• Perception of threat to existing identity\n• Segregation and parallel communities\n• Media portrayal amplifying tensions\n• Named examples from specific places\n• Assessment of balance between opportunities and tensions' },
      { q: 'Assess the effectiveness of regeneration in changing the character and perception of a named place.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of regeneration at a named place with evaluation of effectiveness for different groups.\nLevel 2 (4-6 marks): Some valid points about regeneration with reference to a named place.\nLevel 1 (1-3 marks): Basic points about regeneration.\n\nIndicative content:\n• Named place e.g. London Docklands, Salford Quays, Liverpool\n• Physical transformation of the built environment\n• Economic regeneration: new businesses, employment\n• Social changes: gentrification, displacement\n• Cultural investment: galleries, performance spaces\n• Improved perception through rebranding and media\n• However: benefits may not reach all residents\n• Social inequality may increase\n• Original community may feel displaced\n• Perception differs between insiders and outsiders\n• Assessment of who benefits and who loses' },
      { q: 'Explain how contested place identities can lead to conflict.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with named examples of conflict arising from contested identities.\nLevel 2 (4-6 marks): Some valid points about contested identities.\nLevel 1 (1-3 marks): Basic points with limited explanation.\n\nIndicative content:\n• Different groups have different visions for a place\n• Development vs conservation: new buildings vs heritage preservation\n• Gentrification: existing residents vs newcomers\n• Land use conflicts: housing vs green space\n• Cultural identity: whose history and heritage is represented\n• Named examples of place-based conflicts\n• NIMBYism — "not in my back yard" opposition to change\n• Power dynamics — who has influence over decisions\n• Planning disputes and community campaigns\n• Role of media in fuelling or mediating conflict' },
      { q: 'Explain how the relationship between places at a local and global scale can shape their character.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of local-global connections with clear examples.\nLevel 2 (4-6 marks): Some valid points about connections at different scales.\nLevel 1 (1-3 marks): Basic points about local or global influences.\n\nIndicative content:\n• Global supply chains connect local economies to worldwide markets\n• Transnational corporations shape local employment and services\n• International migration connects distant places\n• Global cultural flows (music, film, food) influence local identity\n• Tourism connects places to global visitor flows\n• Transport links determine global accessibility\n• Digital connectivity enables global connections from local places\n• However, local factors mediate global influences\n• Some places more globalised than others\n• Local resistance to global forces can strengthen distinctive identity' },
      { q: 'Assess the view that places are shaped more by external forces than by local communities.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment with named examples considering both external forces and community agency.\nLevel 2 (4-6 marks): Some consideration of external and/or local factors.\nLevel 1 (1-3 marks): Basic points with limited assessment.\n\nIndicative content:\n• External forces: globalisation, government policy, corporate investment, migration\n• These can dramatically reshape local economies and demographics\n• Deindustrialisation driven by global economic shifts\n• Government policy (e.g. austerity) reduces local services\n• However: local communities resist and shape change\n• Community campaigns protect heritage and character\n• Local entrepreneurs create distinctive businesses\n• Grassroots organisations build social capital\n• Place-based identity can be a force for resilience\n• Named examples of communities shaping their place\n• Assessment: power balance usually favours external forces but local agency matters' },

      // 12-20 mark questions (5)
      { q: 'Evaluate the extent to which people\'s perceptions of place are shaped by their personal circumstances rather than by the actual characteristics of that place.', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated evaluation considering multiple factors that shape perception with detailed examples. Well-structured argument with nuanced conclusion.\nLevel 3 (11-15 marks): Good evaluation with relevant examples.\nLevel 2 (6-10 marks): Some relevant points with limited evaluation.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Personal circumstances: age, gender, ethnicity, class, disability, experience\n• These create unique filters through which places are perceived\n• Same place can be perceived as safe or dangerous by different people\n• Nostalgia and memory shape perception beyond current reality\n• Cultural background influences what is valued in a place\n• However: physical characteristics do shape perception (attractive vs degraded environments)\n• Quality of services and infrastructure affects lived experience for all\n• Environmental quality (air, water, green space) is broadly perceived\n• Media representations create shared perceptions regardless of personal circumstances\n• Extreme deprivation or affluence creates more universal perceptions\n• Named examples illustrating how perception varies\n• Theoretical perspectives: phenomenology, social constructionism\n• Conclusion on the balance between personal and place-based factors' },
      { q: '"Globalisation has destroyed the uniqueness of places." To what extent do you agree with this statement?', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough, balanced discussion with detailed examples of both homogenisation and enduring distinctiveness. Well-reasoned conclusion.\nLevel 3 (11-15 marks): Good discussion with relevant examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Evidence for: clone towns, global chains, standardised architecture\n• Cultural globalisation creating homogeneous consumer landscapes\n• Digital connectivity reducing the distinctiveness of experience\n• Global media creating shared cultural references\n• Evidence against: local cultures adapt and resist\n• Glocalisation — global brands adapt to local contexts\n• Heritage conservation and protection of unique character\n• Place branding emphasises distinctiveness\n• Natural landscapes remain unique\n• Cultural traditions and festivals maintain identity\n• Migration creates new forms of uniqueness rather than destroying it\n• Different scales — local uniqueness persists within global trends\n• Named examples of places resisting or embracing globalisation\n• Assessment of the extent — partial truth but oversimplification\n• Theoretical perspectives on place and globalisation' },
      { q: 'Discuss the extent to which regeneration and rebranding can successfully change the identity of a place. Use named examples in your answer.', marks: 20, markScheme: 'Level 4 (16-20 marks): Detailed discussion with multiple named examples, considering success from different perspectives. Evaluative conclusion about the extent of successful change.\nLevel 3 (11-15 marks): Good discussion with named examples.\nLevel 2 (6-10 marks): Some relevant points with limited examples.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Named examples of regeneration: London Docklands, Salford Quays, Liverpool, Barcelona\n• Physical transformation: new buildings, infrastructure, public spaces\n• Economic change: new industries, employment, investment\n• Rebranding: marketing campaigns, cultural events, place narratives\n• Success measures: economic indicators, perception surveys, quality of life\n• However: gentrification can displace original communities\n• Benefits may not be equally shared\n• Original identity may be lost in the process\n• Whose identity is being created — for residents or visitors?\n• Surface-level change vs deep structural transformation\n• Time lag between rebranding and genuine perception change\n• Some stigma persists despite investment\n• Community resistance to imposed new identities\n• Role of media in shaping perception of regenerated places\n• Conclusion on extent to which identity can truly be changed' },
      { q: 'To what extent do places reflect the power dynamics of the societies that create them?', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated discussion of how power dynamics shape places with detailed examples and theoretical understanding. Nuanced conclusion.\nLevel 3 (11-15 marks): Good discussion with relevant examples.\nLevel 2 (6-10 marks): Some relevant points about power and place.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Wealthy groups shape places through investment and development\n• Planning decisions reflect power structures\n• Gated communities as spatial expression of inequality\n• Heritage selection — whose history is preserved and celebrated\n• Naming of places and monuments reflects power\n• Colonial legacies in place character and urban form\n• Gentrification as displacement of less powerful groups\n• Corporate power shapes high streets and commercial areas\n• Government policy reflects political priorities\n• Marginalised groups excluded from place-making decisions\n• However: community action can challenge power dynamics\n• Public spaces as democratic and accessible\n• Grassroots place-making and guerrilla gardening\n• Named examples of how power dynamics are visible in specific places\n• Theoretical perspectives: Harvey, Massey, Cresswell\n• Conclusion on the extent of power\'s influence on place' },
      { q: 'Evaluate the view that the study of place is essentially subjective and therefore cannot produce valid geographical knowledge.', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated evaluation of epistemological issues in place study with reference to different approaches. Well-reasoned conclusion.\nLevel 3 (11-15 marks): Good evaluation of subjectivity in place study.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Subjective elements: personal experience, perception, emotional attachment\n• Qualitative methods capture subjective dimensions\n• Phenomenological approaches prioritise lived experience\n• Different people experience the same place differently\n• However: quantitative data provides objective measurement\n• Census data, economic statistics are measurable and comparable\n• Physical geography is objectively real\n• Mixed methods combine subjective and objective approaches\n• Both types of knowledge are valid in geography\n• Subjectivity is a feature not a flaw — it reveals important truths\n• Systematic study of perceptions is rigorous methodology\n• Triangulation of data sources improves validity\n• Other social sciences face similar epistemological challenges\n• Named geographers and their perspectives on place study\n• Conclusion: place study requires both subjective and objective approaches' },
    ],
  },
  '2.2': {
    name: 'Contemporary Urban Environments',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two characteristics of urban sprawl.', marks: 2, markScheme: '• Low-density development on the outskirts of a city (1)\n• Car-dependent, often with commercial strips and housing estates (1)' },
      { q: 'Define the term "urbanisation".', marks: 2, markScheme: '• The increase in the proportion of a population living in urban areas (1)\n• As a result of rural-to-urban migration and/or natural increase in cities (1)' },
      { q: 'State two environmental problems associated with rapid urban growth in LICs.', marks: 2, markScheme: '• Water pollution from inadequate sewage systems (1)\n• Air pollution from industry, vehicles, and burning waste (1)' },
      { q: 'Define the term "urban heat island".', marks: 3, markScheme: '• An urban area that is significantly warmer than surrounding rural areas (1)\n• Due to human activities, building materials absorbing heat, and reduced vegetation (1)\n• Temperatures can be 2-5°C higher in the city centre (1)' },
      { q: 'State two features of a sustainable urban transport system.', marks: 2, markScheme: '• Integrated public transport network (buses, trams, metro) (1)\n• Cycling infrastructure / pedestrianised areas / low emission zones (1)' },
      { q: 'Define the term "counter-urbanisation".', marks: 2, markScheme: '• The movement of people from large urban areas to smaller towns and rural areas (1)\n• Leading to population decline in city centres and growth in surrounding areas (1)' },
      { q: 'State two push factors causing rural-to-urban migration in LICs.', marks: 2, markScheme: '• Lack of employment opportunities in rural areas (1)\n• Limited access to services (healthcare, education) / natural hazards / land shortages (1)' },
      { q: 'Define the term "gentrification".', marks: 3, markScheme: '• The process of renovation and improvement of a deteriorated urban neighbourhood (1)\n• By wealthier newcomers moving into the area (1)\n• Often leading to displacement of existing lower-income residents (1)' },
      { q: 'State two social problems commonly found in urban areas.', marks: 2, markScheme: '• Crime and antisocial behaviour (1)\n• Social inequality / segregation / homelessness / overcrowding (1)' },
      { q: 'Define the term "deindustrialisation".', marks: 2, markScheme: '• The decline of manufacturing/industrial activity in an area or economy (1)\n• Leading to factory closures, unemployment, and economic restructuring (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain the causes and consequences of the urban heat island effect.', marks: 6, markScheme: '• Dark surfaces (tarmac, roofs) absorb and re-radiate heat (1)\n• Buildings trap heat through the canyon effect (1)\n• Less vegetation means less evapotranspiration cooling (1)\n• Waste heat from vehicles, industry, air conditioning (1)\n• Consequences: increased energy demand for cooling (1)\n• Health risks — heat stress, especially for elderly and vulnerable (1)\n• Enhanced convectional rainfall in urban areas (1)\n• Poorer air quality as heat accelerates chemical reactions (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the processes that lead to the formation of urban microclimates.', marks: 6, markScheme: '• Urban surfaces absorb and retain heat — urban heat island (1)\n• Buildings create wind tunnels (Venturi effect) and sheltered areas (1)\n• Air pollution creates a dust dome trapping pollutants and heat (1)\n• Reduced evapotranspiration from limited vegetation (1)\n• Higher rainfall from convection and enhanced condensation nuclei (1)\n• Fog and lower sunshine hours due to pollution (1)\n• Height and density of buildings affect sunlight and temperature (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain how urban areas can contribute to increased flood risk.', marks: 6, markScheme: '• Impermeable surfaces (concrete, tarmac) increase surface runoff (1)\n• Reduced infiltration and natural drainage (1)\n• Drains and sewers can be overwhelmed during heavy rainfall (1)\n• Removal of vegetation reduces interception (1)\n• Building on floodplains increases exposure (1)\n• Urban heat island effect can increase convectional rainfall intensity (1)\n• Climate change increasing extreme rainfall events in urban areas (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Describe the main features of the Burgess concentric zone model of urban structure.', marks: 4, markScheme: '• CBD at the centre — commercial and retail core (1)\n• Inner city / transition zone — older housing, industry (1)\n• Inner suburbs — working-class housing (1)\n• Outer suburbs — middle-class housing, newer development (1)\n• Commuter zone at the edge (1)\n• Model based on Chicago in 1920s (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain the causes and impacts of urban deprivation.', marks: 6, markScheme: '• Deindustrialisation leading to unemployment (1)\n• Low incomes and poverty trapping residents (1)\n• Poor housing quality — overcrowding, damp, disrepair (1)\n• Limited access to quality education and healthcare (1)\n• Higher crime rates and antisocial behaviour (1)\n• Social exclusion and reduced social mobility (1)\n• Environmental degradation — pollution, lack of green space (1)\n• Cycle of deprivation is self-reinforcing (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain how sustainable urban drainage systems (SuDS) help manage urban flooding.', marks: 5, markScheme: '• Permeable paving allows water to infiltrate through surfaces (1)\n• Swales and rain gardens collect and store runoff temporarily (1)\n• Green roofs absorb rainfall and reduce runoff (1)\n• Retention ponds store water during peak flow (1)\n• Mimics natural drainage processes — slows flow and increases infiltration (1)\n• Reduces pressure on conventional drainage systems (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain the social and economic impacts of gentrification.', marks: 6, markScheme: '• Property values and rents increase (1)\n• Original lower-income residents may be priced out / displaced (1)\n• New businesses and services cater to wealthier newcomers (1)\n• Physical improvement of buildings and streetscape (1)\n• Reduced crime rates and improved services (1)\n• Social tensions between existing and new residents (1)\n• Loss of community identity and local culture (1)\n• Increased social polarisation / inequality (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Describe the pattern of urban growth in one named city in a LIC or NEE.', marks: 4, markScheme: '• Named city e.g. Lagos, Mumbai, São Paulo (1)\n• Rapid growth driven by rural-to-urban migration and natural increase (1)\n• Informal settlements / slums on the periphery or marginal land (1)\n• Commercial CBD with surrounding industrial and residential zones (1)\n• Infrastructure struggling to keep pace with growth (1)\n• Credit specific detail from named city, max 4 marks' },
      { q: 'Sketch and annotate a diagram to show the characteristics of an urban heat island.', marks: 5, diagram: true, markScheme: '• Cross-section showing temperature profile across urban area (1)\n• Higher temperatures in the city centre / CBD (1)\n• Cooler temperatures in parks / green spaces shown as dips (1)\n• Cooler rural areas on the edges (1)\n• Annotations explaining causes (dark surfaces, waste heat, lack of vegetation) (1)\n• Scale or temperature difference indicated (1)\n• Credit any valid features, max 5 marks' },
      { q: 'Explain the challenges of waste management in urban areas.', marks: 5, markScheme: '• Large volumes of waste generated by dense populations (1)\n• Landfill sites becoming full and new sites hard to find (1)\n• Recycling rates vary and contamination reduces effectiveness (1)\n• Collection logistics in congested urban areas (1)\n• Hazardous and electronic waste requires specialist disposal (1)\n• Cost of waste management for local authorities (1)\n• In LICs: informal waste disposal, open dumping, health hazards (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain the concept of ecological footprint in relation to urban areas.', marks: 4, markScheme: '• Ecological footprint measures the land area needed to sustain a population\'s resource consumption (1)\n• Urban areas typically have large ecological footprints due to high consumption (1)\n• Cities rely on resources from far beyond their boundaries (1)\n• Includes food production, energy, waste processing, water supply (1)\n• Urban living can be more efficient per capita than rural (density, shared services) (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain two strategies for making urban transport more sustainable.', marks: 6, markScheme: '• Integrated public transport — connecting buses, trams, metro systems (1)\n• This reduces private car use and emissions (1)\n• Congestion charging — charges vehicles entering city centre (1)\n• Discourages car use and funds public transport (1)\n• Cycling infrastructure — dedicated lanes, bike-sharing schemes (1)\n• Low/zero emission vehicle incentives (1)\n• Park and ride schemes reduce inner city traffic (1)\n• Credit two strategies fully explained, max 6 marks' },
      { q: 'Explain how green infrastructure can improve urban environments.', marks: 5, markScheme: '• Urban parks and green spaces provide recreation and improve wellbeing (1)\n• Trees provide shade, reduce urban heat island effect (1)\n• Green corridors enable wildlife movement through urban areas (1)\n• Green roofs and walls insulate buildings and absorb rainwater (1)\n• Vegetation improves air quality by filtering pollutants (1)\n• Green spaces can increase property values and attract investment (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Describe the main characteristics of a named urban regeneration project.', marks: 6, markScheme: '• Named regeneration project e.g. London Docklands, Salford Quays, Temple Quarter Bristol (1)\n• Physical changes to the built environment (1)\n• Economic changes — new businesses, employment (1)\n• Social changes — housing, community facilities (1)\n• Environmental improvements (1)\n• Specific details of the named project (1)\n• Scale and cost of the project (1)\n• Credit specific detail, max 6 marks' },
      { q: 'Explain why urban areas in LICs often experience rapid and unplanned growth.', marks: 4, markScheme: '• High rates of rural-to-urban migration seeking employment and services (1)\n• Natural increase — young migrant population with high birth rates (1)\n• Lack of planning capacity and resources to manage growth (1)\n• Informal settlements develop on marginal land without regulation (1)\n• Government unable to provide infrastructure at pace of growth (1)\n• Credit any valid points, max 4 marks' },

      // 8-9 mark questions (10)
      { q: 'Assess the social and environmental impacts of rapid urbanisation in a named city in a LIC or NEE.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of both social and environmental impacts with specific detail from a named city.\nLevel 2 (4-6 marks): Some valid points with reference to a named city.\nLevel 1 (1-3 marks): Basic points with limited reference to a specific city.\n\nIndicative content:\n• Named city e.g. Lagos, Mumbai, São Paulo\n• Social impacts: housing shortages, informal settlements, inequality\n• Overcrowding and strain on services (healthcare, education)\n• Employment in informal sector — low wages, poor conditions\n• Social tensions and crime\n• Environmental impacts: air and water pollution\n• Inadequate waste management\n• Deforestation and habitat loss on urban fringe\n• Water supply and sanitation challenges\n• However: also opportunities — economic growth, improved services for some\n• Assessment of balance between positive and negative impacts' },
      { q: 'Explain the causes and consequences of social segregation within urban areas.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of multiple causes and consequences with named examples.\nLevel 2 (4-6 marks): Some causes and consequences identified.\nLevel 1 (1-3 marks): Basic points with limited development.\n\nIndicative content:\nCauses:\n• Income inequality — housing affordability determines location\n• Historical patterns of settlement\n• Discrimination in housing markets\n• Self-segregation — desire to live near similar people\n• Planning decisions and housing policy\n• Gentrification pushing lower-income groups to periphery\nConsequences:\n• Unequal access to services and opportunities\n• Educational inequality between areas\n• Health inequalities\n• Reduced social cohesion and understanding\n• Political marginalisation of deprived areas\n• Spatial patterns of crime and deprivation\n• Named examples of segregated urban areas' },
      { q: 'Assess the effectiveness of strategies used to manage urban sustainability in a named city.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple strategies with evaluation of effectiveness at a named city.\nLevel 2 (4-6 marks): Some strategies discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of strategies.\n\nIndicative content:\n• Named city e.g. Freiburg, Curitiba, Singapore, Copenhagen\n• Transport strategies: public transport, cycling, congestion charging\n• Energy: renewable energy, energy efficiency in buildings\n• Water management: SuDS, water recycling\n• Waste: recycling programmes, waste-to-energy\n• Green infrastructure: parks, green roofs, urban forests\n• Planning: mixed-use development, compact city design\n• Assessment of effectiveness: what has worked well\n• Limitations and ongoing challenges\n• Transferability to other cities\n• Cost and political feasibility' },
      { q: 'Explain how urban areas can be planned and managed to reduce their environmental impact.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple strategies with clear links to environmental impact reduction.\nLevel 2 (4-6 marks): Some strategies explained.\nLevel 1 (1-3 marks): Basic identification of strategies.\n\nIndicative content:\n• Green belts and compact city design to reduce sprawl\n• Sustainable transport: public transport, cycling, EVs\n• Green infrastructure: parks, urban forests, green roofs\n• Sustainable drainage systems (SuDS)\n• Waste management: reduce, reuse, recycle hierarchy\n• Energy-efficient buildings and renewable energy\n• Water conservation and recycling\n• Air quality management zones\n• Urban food production — allotments, vertical farming\n• Planning regulations and building standards\n• Smart city technology for resource management' },
      { q: 'Assess the extent to which urban regeneration benefits all members of the community.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment considering benefits and drawbacks for different groups with named examples.\nLevel 2 (4-6 marks): Some consideration of who benefits.\nLevel 1 (1-3 marks): Basic points about regeneration.\n\nIndicative content:\n• Physical improvements benefit the whole area (public realm, infrastructure)\n• New employment opportunities\n• Improved services and amenities\n• However: gentrification displaces original residents\n• Rising property values and rents exclude lower-income groups\n• New jobs may not match skills of local residents\n• Trickle-down economics may not work in practice\n• Community facilities may change to serve newcomers\n• Cultural displacement alongside physical changes\n• Named examples of regeneration with mixed outcomes\n• Assessment of for whom regeneration works' },
      { q: 'Explain the factors that influence patterns of economic inequality within urban areas.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple factors with clear links to spatial patterns.\nLevel 2 (4-6 marks): Some factors explained.\nLevel 1 (1-3 marks): Basic identification of factors.\n\nIndicative content:\n• Historical development patterns — industrial legacy areas\n• Housing market dynamics — price variations create spatial inequality\n• Transport accessibility affects employment opportunities\n• Quality of local schools affects social mobility\n• Discrimination in employment and housing\n• Government policy: regeneration investment, welfare\n• Deindustrialisation concentrated in specific areas\n• Suburbanisation of wealth leaving inner city deprivation\n• Or gentrification displacing poverty to the periphery\n• Cumulative causation — deprivation reinforces itself\n• Global economic connections benefit some areas more than others' },
      { q: 'Assess the challenges and opportunities of managing urban waste sustainably.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of both challenges and opportunities with named examples.\nLevel 2 (4-6 marks): Some valid points about waste management.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\nChallenges:\n• Growing volumes of waste from increasing consumption\n• Limited landfill capacity in urban areas\n• Cost of advanced treatment technologies\n• Contamination reducing recycling effectiveness\n• Changing composition of waste (electronics, plastics)\n• Public engagement and behaviour change\nOpportunities:\n• Circular economy — designing out waste\n• Waste-to-energy technology\n• High recycling rates achievable (see Germany, Sweden)\n• Economic opportunities in recycling industry\n• Composting organic waste\n• Technology for waste sorting and processing\n• Named examples of successful waste management cities\n• Assessment of whether zero waste is achievable' },
      { q: 'Explain how urban growth can affect the biodiversity of an area.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of both negative and positive impacts on biodiversity.\nLevel 2 (4-6 marks): Some valid points.\nLevel 1 (1-3 marks): Basic points with limited explanation.\n\nIndicative content:\nNegative impacts:\n• Habitat destruction from land clearance for building\n• Fragmentation of habitats by roads and development\n• Pollution of water, air, and soil\n• Light and noise pollution disturbing wildlife\n• Introduction of non-native species\nPositive impacts:\n• Urban green spaces can support surprising biodiversity\n• Gardens, parks, and brownfield sites as wildlife habitats\n• Urban species adaptation (e.g. urban foxes, peregrine falcons)\n• Green corridors can connect habitats\n• Conservation initiatives in urban areas\n• SuDS and green infrastructure supporting biodiversity\n• Urban areas can protect species from agricultural intensification' },
      { q: 'Explain the importance of urban design and planning in creating liveable cities.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of how design and planning contribute to liveability with examples.\nLevel 2 (4-6 marks): Some valid points about urban design.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\n• Mixed-use development reduces commuting and creates vibrant neighbourhoods\n• Public spaces — plazas, parks, waterfronts — promote wellbeing\n• Walkable neighbourhoods reduce car dependence\n• Affordable housing provision reduces inequality\n• Green infrastructure improves air quality and mental health\n• Inclusive design ensures accessibility for all\n• Safety through environmental design (CPTED)\n• Cultural facilities enhance quality of life\n• Named examples of well-designed cities (Copenhagen, Barcelona)\n• Planning prevents uncontrolled growth and environmental degradation\n• Community involvement in planning improves outcomes' },
      { q: 'Assess the view that urban areas in LICs face fundamentally different challenges to those in HICs.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment comparing challenges in LICs and HICs with named examples.\nLevel 2 (4-6 marks): Some comparison with partial assessment.\nLevel 1 (1-3 marks): Basic points about LIC or HIC urban challenges.\n\nIndicative content:\nLIC challenges:\n• Rapid unplanned growth — informal settlements\n• Basic infrastructure gaps: water, sanitation, electricity\n• Informal employment and extreme poverty\n• Limited government capacity to manage growth\nHIC challenges:\n• Ageing infrastructure requiring replacement\n• Inequality and social segregation\n• Deindustrialisation and economic restructuring\n• Urban sprawl and environmental sustainability\nSimilarities:\n• Both face climate change impacts\n• Both have inequality and social challenges\n• Both need sustainable transport solutions\n• Scale and nature differ but core issues overlap\n• Assessment of whether challenges are fundamentally different or different in degree' },

      // 12-20 mark questions (5)
      { q: 'Evaluate the success of urban regeneration strategies in addressing social inequality in cities. Use named examples in your answer.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough evaluation with multiple named examples examining regeneration outcomes from different perspectives. Well-evidenced conclusion.\nLevel 3 (11-15 marks): Good evaluation with named examples.\nLevel 2 (6-10 marks): Some relevant points with limited examples.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Named examples of regeneration: London Docklands, Salford Quays, Olympic Park, Liverpool, Barcelona\n• Physical improvements: housing, infrastructure, public space\n• Economic outcomes: employment, investment, business growth\n• Social outcomes: healthcare, education, community facilities\n• Gentrification and displacement as unintended consequences\n• Rising property values pricing out original residents\n• Jobs created may not match local skills\n• Cultural displacement alongside physical changes\n• Community-led vs top-down regeneration\n• Measuring success: for whom and by what criteria?\n• Short-term vs long-term outcomes\n• Role of government policy and funding\n• Trickle-down vs targeted approaches\n• Evaluation of whether inequality is reduced or merely relocated' },
      { q: '"Sustainable urban living is possible but requires fundamental changes to the way cities are designed and managed." Discuss this statement.', marks: 20, markScheme: 'Level 4 (16-20 marks): Comprehensive discussion with detailed examples of sustainable urban strategies. Evaluation of whether fundamental change is needed and achievable.\nLevel 3 (11-15 marks): Good discussion with relevant examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Current urban challenges: emissions, waste, resource consumption\n• Transport: shift from cars to public transport, cycling, walking\n• Energy: renewable energy, efficient buildings, district heating\n• Water: SuDS, recycling, conservation\n• Waste: circular economy, zero waste initiatives\n• Green infrastructure: urban forests, green roofs, biodiversity corridors\n• Planning: compact city, mixed-use, transit-oriented development\n• Named exemplar cities: Freiburg, Curitiba, Copenhagen, Singapore\n• Scale of change required is immense\n• Existing infrastructure is difficult to retrofit\n• Economic and political barriers to change\n• Social justice considerations — who bears the costs?\n• Incremental change vs transformational change\n• Technology as enabler or distraction\n• Conclusion on feasibility and desirability of fundamental change' },
      { q: 'To what extent is rapid urban growth in LICs creating more opportunities than problems? Use named examples in your answer.', marks: 20, markScheme: 'Level 4 (16-20 marks): Balanced evaluation considering both opportunities and problems with specific named city examples. Nuanced conclusion.\nLevel 3 (11-15 marks): Good discussion with named examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\nOpportunities:\n• Economic growth and employment — formal and informal sector\n• Improved access to services: education, healthcare\n• Social mobility and cultural exchange\n• Infrastructure development\n• Innovation and entrepreneurship\nProblems:\n• Informal settlements with poor living conditions\n• Environmental degradation: pollution, waste, deforestation\n• Strain on infrastructure: water, sanitation, transport\n• Social inequality and crime\n• Health problems from overcrowding and pollution\n• Named city examples: Lagos, Mumbai, São Paulo, Nairobi\n• Specific data and evidence from named cities\n• Different outcomes for different groups\n• Role of governance in determining outcomes\n• Long-term trajectory — problems may reduce as development progresses\n• Comparison with historical urbanisation in now-HICs' },
      { q: 'Discuss the extent to which urban areas can be considered as ecosystems in their own right.', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated discussion applying ecological concepts to urban areas with detailed examples. Evaluative conclusion.\nLevel 3 (11-15 marks): Good application of ecosystem concepts with examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Urban areas have inputs, outputs, and stores of energy and materials\n• Urban metabolism — resource consumption and waste production\n• Ecological footprint extends far beyond city boundaries\n• Urban biodiversity — adapted species, gardens, parks\n• Urban food webs and trophic levels\n• Nutrient cycling in urban soils and water systems\n• Urban microclimate as ecosystem feature\n• Green and blue infrastructure as ecological components\n• However: cities are open systems reliant on external inputs\n• Unlike natural ecosystems — not self-sustaining\n• Heavily managed and modified by human activity\n• Ecosystem services in urban areas\n• Named examples of urban ecological initiatives\n• Theoretical perspectives: urban ecology, ecosystem services\n• Conclusion on the validity and usefulness of the ecosystem concept' },
      { q: 'Evaluate the view that urban planning models are of limited value in understanding the structure of modern cities.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough evaluation of urban models with assessment of their relevance to modern cities. Well-structured argument with conclusion.\nLevel 3 (11-15 marks): Good evaluation of models with some modern application.\nLevel 2 (6-10 marks): Some relevant points about models.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Burgess concentric zone model: based on 1920s Chicago\n• Hoyt sector model: adds transport routes\n• Harris and Ullman multiple nuclei model: more complex\n• Models provide simplified frameworks for understanding\n• However: based on specific historical contexts (US cities)\n• Don\'t account for cultural, political, economic differences\n• Modern cities are more complex and polycentric\n• Globalisation has changed urban structure\n• LIC cities don\'t follow the same patterns\n• Edge cities, suburban employment centres not predicted\n• Models don\'t account for planning intervention\n• Gentrification reverses predicted patterns\n• However: basic principles (accessibility, land values) still relevant\n• Models useful as starting points for analysis\n• Modern GIS and data-driven approaches complement models\n• Conclusion on the extent of value and limitations' },
    ],
  },
  '2.3': {
    name: 'Population & the Environment',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two environmental factors that influence the global distribution of population.', marks: 2, markScheme: '• Climate — moderate temperatures and reliable rainfall support dense populations (1)\n• Relief — flat, lowland areas are more densely populated than mountainous terrain (1)' },
      { q: 'Define the term "carrying capacity".', marks: 2, markScheme: '• The maximum population that an environment/area can sustain (1)\n• Given the available resources (food, water, energy) without degradation (1)' },
      { q: 'State two characteristics of Stage 1 of the Demographic Transition Model.', marks: 2, markScheme: '• High birth rate (1)\n• High death rate / low population growth / fluctuating population (1)' },
      { q: 'Define the term "food security".', marks: 2, markScheme: '• When all people at all times have access to sufficient, safe, and nutritious food (1)\n• To maintain a healthy and active life (1)' },
      { q: 'State two health risks associated with rapid population growth in LICs.', marks: 2, markScheme: '• Spread of infectious diseases due to overcrowding and poor sanitation (1)\n• Malnutrition from food insecurity / lack of clean water (1)' },
      { q: 'Define the term "optimum population".', marks: 3, markScheme: '• The population size that produces the maximum sustainable standard of living (1)\n• Given the available resources and technology (1)\n• Neither overpopulated nor underpopulated (1)' },
      { q: 'State two ways in which population growth can affect the environment.', marks: 2, markScheme: '• Deforestation to create agricultural land (1)\n• Increased pollution from industry and waste (1)' },
      { q: 'Define the term "dependency ratio".', marks: 2, markScheme: '• The ratio of economically inactive (young and old) to economically active population (1)\n• Calculated as (0-14 + 65+) / (15-64) × 100 (1)' },
      { q: 'State two reasons why some countries experience population decline.', marks: 2, markScheme: '• Low birth rates below replacement level (1)\n• Out-migration / ageing population / high death rates (1)' },
      { q: 'Define the term "ecological footprint".', marks: 3, markScheme: '• A measure of human demand on the Earth\'s natural resources (1)\n• Expressed as the area of biologically productive land and water (1)\n• Required to produce resources consumed and absorb waste generated (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain the relationship between population growth and environmental degradation.', marks: 6, markScheme: '• Growing populations increase demand for food, water, and energy (1)\n• Deforestation for agriculture and settlement (1)\n• Overgrazing leads to desertification in arid areas (1)\n• Increased emissions from energy use and transport (1)\n• Water pollution from sewage and agricultural chemicals (1)\n• Soil erosion from intensive farming practices (1)\n• Biodiversity loss from habitat destruction (1)\n• However: technology and management can reduce per-capita impacts (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the main features and limitations of Malthus\'s theory of population growth.', marks: 6, markScheme: '• Population grows geometrically/exponentially (1)\n• Food production grows arithmetically/linearly (1)\n• Population will outstrip food supply (1)\n• Positive checks: famine, disease, war reduce population (1)\n• Preventive checks: moral restraint limits growth (1)\n• Limitations: didn\'t foresee agricultural revolution / Green Revolution (1)\n• Technology has increased food production beyond linear growth (1)\n• Trade allows food to be imported / unevenly distributed resources (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain how climate change could affect global food production.', marks: 6, markScheme: '• Rising temperatures may reduce crop yields in tropical regions (1)\n• Some temperate regions may benefit from longer growing seasons (1)\n• Changing rainfall patterns disrupt irrigation and rainfed agriculture (1)\n• More frequent extreme weather events damage crops (1)\n• Rising CO2 may boost some crop growth but reduce nutritional quality (1)\n• Sea level rise threatens low-lying agricultural land (1)\n• Pest and disease ranges expand with warming (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the concept of Boserup\'s theory and how it contrasts with Malthus.', marks: 4, markScheme: '• Boserup argued that "necessity is the mother of invention" (1)\n• Population growth drives agricultural innovation and intensification (1)\n• People will find ways to increase food production when needed (1)\n• This contrasts with Malthus who saw population as limited by food supply (1)\n• Boserup is more optimistic about human ingenuity and adaptation (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain the environmental impacts of intensive agriculture.', marks: 6, markScheme: '• Soil degradation from over-cultivation and chemical use (1)\n• Water pollution from fertilisers (eutrophication) and pesticides (1)\n• Loss of biodiversity from monoculture and habitat removal (1)\n• Deforestation to expand agricultural land (1)\n• Greenhouse gas emissions from machinery, livestock, fertilisers (1)\n• Water depletion from irrigation (aquifer depletion) (1)\n• Loss of soil organic matter and structure (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Describe how the age-sex structure of a population changes as a country develops.', marks: 4, markScheme: '• LICs: wide base (high birth rate), narrow top (low life expectancy) (1)\n• As country develops: base narrows as birth rate falls (1)\n• Middle section widens as more people survive to working age (1)\n• Top widens as life expectancy increases with development (1)\n• HICs: more rectangular/pillar shape or even narrowing base (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain the causes of food insecurity in LICs.', marks: 6, markScheme: '• Rapid population growth outpacing food production (1)\n• Climate variability — drought, flooding affecting harvests (1)\n• Conflict and political instability disrupting agriculture (1)\n• Poverty — inability to purchase food even when available (1)\n• Poor agricultural technology and infrastructure (1)\n• Land degradation from overuse and poor management (1)\n• Trade barriers and unfair global trade systems (1)\n• Post-harvest losses due to poor storage and transport (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the environmental impacts of energy production.', marks: 5, markScheme: '• Fossil fuel combustion releases CO2 and other greenhouse gases (1)\n• Air pollution from power stations (SO2, NOx, particulates) (1)\n• Water pollution from mining and processing (1)\n• Land degradation from surface mining and drilling (1)\n• Nuclear waste disposal creates long-term contamination risk (1)\n• Hydroelectric dams alter river ecosystems and flood land (1)\n• Even renewables have impacts (wind turbines on birds, solar on land use) (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Draw an annotated diagram of the Demographic Transition Model showing all five stages.', marks: 6, diagram: true, markScheme: '• Axes correctly labelled: birth/death rate and time/stage (1)\n• Stage 1: high BR and DR, low growth (1)\n• Stage 2: high BR, falling DR, rapid growth (1)\n• Stage 3: falling BR, low DR, slowing growth (1)\n• Stage 4: low BR and DR, stable population (1)\n• Stage 5: BR below DR, population decline shown (1)\n• Total population line shown increasing then levelling/declining (1)\n• Credit any valid annotations, max 6 marks' },
      { q: 'Explain how water scarcity can affect human health and development.', marks: 5, markScheme: '• Waterborne diseases spread when water sources are contaminated (1)\n• Inadequate sanitation linked to diarrhoeal diseases (1)\n• Malnutrition from inability to irrigate crops (1)\n• Time spent collecting water reduces education and economic activity (1)\n• Conflict over water resources hinders development (1)\n• Women and children disproportionately affected (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain the concept of the epidemiological transition.', marks: 4, markScheme: '• Shift in the dominant types of disease as countries develop (1)\n• From infectious/communicable diseases (cholera, malaria) in LICs (1)\n• To degenerative/non-communicable diseases (heart disease, cancer) in HICs (1)\n• Linked to improved sanitation, healthcare, and changing lifestyles (1)\n• Mirrors the demographic transition — falling death rates (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain why global population growth rates vary between regions.', marks: 6, markScheme: '• Sub-Saharan Africa: high growth due to high birth rates and improving death rates (1)\n• Cultural/religious factors encouraging large families (1)\n• Limited access to family planning and contraception (1)\n• Europe: low/negative growth due to below-replacement birth rates (1)\n• Women\'s education and economic empowerment reduce birth rates (1)\n• Access to contraception and healthcare in HICs (1)\n• Government policies (pro-natalist or anti-natalist) affect rates (1)\n• Stage of demographic transition influences growth rate (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the concept of over-population and give one example.', marks: 4, markScheme: '• Over-population occurs when a population exceeds the carrying capacity (1)\n• Resources are insufficient to sustainably support the population (1)\n• Leads to environmental degradation, resource depletion, poverty (1)\n• Example: Bangladesh — high population density, limited resources, flood vulnerability (1)\n• Or: parts of Sub-Saharan Africa facing food insecurity (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain how globalisation affects global food supply patterns.', marks: 5, markScheme: '• International trade enables food to be transported globally (1)\n• Consumers access products from all over the world year-round (1)\n• Transnational corporations dominate global food supply chains (1)\n• Cash crop production for export can reduce local food security (1)\n• Trade agreements and subsidies create unequal competition (1)\n• Food miles increase — environmental impact of transport (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain the link between population growth, energy demand, and environmental sustainability.', marks: 6, markScheme: '• More people require more energy for heating, cooking, transport, industry (1)\n• Fossil fuel use increases with population growth if energy mix unchanged (1)\n• Rising emissions contribute to climate change (1)\n• Resource depletion — finite fossil fuels consumed faster (1)\n• Energy poverty — many in LICs lack access to modern energy (1)\n• Transition to renewables needed for sustainability (1)\n• Per capita energy use matters — small HIC populations consume more than large LIC populations (1)\n• Credit any valid points, max 6 marks' },

      // 8-9 mark questions (10)
      { q: 'Assess the view that population growth is the main cause of environmental degradation.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment considering population growth alongside other factors, with evaluative conclusion.\nLevel 2 (4-6 marks): Some consideration of factors with partial assessment.\nLevel 1 (1-3 marks): Basic points with limited assessment.\n\nIndicative content:\n• Population growth increases demand for resources — food, water, energy, land\n• Deforestation, soil degradation, water pollution from expanding populations\n• However: consumption patterns matter more than numbers\n• A small population with high consumption can cause more damage\n• Technology and governance mediate the relationship\n• IPAT equation: Impact = Population × Affluence × Technology\n• Wealthiest 10% responsible for majority of emissions\n• Industrial processes and economic systems drive degradation\n• Poverty can also cause environmental degradation\n• Assessment: population is one factor but not necessarily the main one\n• Named examples supporting different perspectives' },
      { q: 'Explain how different theories (Malthus, Boserup, Club of Rome) approach the relationship between population and resources.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of multiple theories with clear comparison and evaluation.\nLevel 2 (4-6 marks): Some theories explained with partial comparison.\nLevel 1 (1-3 marks): Basic identification of theories.\n\nIndicative content:\n• Malthus: population growth outstrips food supply → positive checks\n• Pessimistic — resources are finite constraints on population\n• Boserup: population pressure drives agricultural innovation\n• Optimistic — human ingenuity overcomes resource constraints\n• Club of Rome / Limits to Growth: computer modelling of resource depletion\n• Predicted collapse if growth patterns continue\n• Neo-Malthusians: updated concerns about global environmental limits\n• Cornucopians: technology will solve resource problems\n• Evidence supporting and contradicting each theory\n• Assessment of which has been most accurate\n• Relevance of each theory to current global challenges' },
      { q: 'Assess the effectiveness of strategies to achieve food security at different scales.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of strategies at local, national, and global scales with evaluation of effectiveness.\nLevel 2 (4-6 marks): Some strategies discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of strategies.\n\nIndicative content:\nLocal:\n• Community farming and allotments\n• Improved storage and post-harvest processing\n• Small-scale irrigation projects\nNational:\n• Agricultural subsidies and investment\n• Land reform and redistribution\n• Green Revolution technologies\n• National food reserves and buffer stocks\nGlobal:\n• International food aid and development programmes\n• Fair trade agreements\n• GM crops and biotechnology\n• Climate change adaptation in agriculture\n• Assessment of effectiveness at each scale\n• Sustainability and equity considerations\n• Named examples of successful and unsuccessful strategies' },
      { q: 'Explain the causes and consequences of global water stress.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of both causes and consequences with named examples.\nLevel 2 (4-6 marks): Some valid points about causes and/or consequences.\nLevel 1 (1-3 marks): Basic identification of causes or consequences.\n\nIndicative content:\nCauses:\n• Population growth increasing demand\n• Agricultural irrigation — 70% of global water use\n• Industrial water use in manufacturing\n• Climate change altering precipitation patterns\n• Pollution reducing usable water supply\n• Groundwater over-abstraction\nConsequences:\n• Water rationing and supply shortages\n• Conflict over water resources\n• Agricultural productivity decline — food insecurity\n• Health impacts from contaminated or insufficient water\n• Environmental degradation of rivers and wetlands\n• Economic costs of water treatment and infrastructure\n• Named examples: Cape Town, Aral Sea, Middle East' },
      { q: 'Assess the extent to which population policies have been successful in managing population change.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of different policies with evaluation of success, using named examples.\nLevel 2 (4-6 marks): Some policies discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of policies.\n\nIndicative content:\n• China\'s one-child policy: reduced growth but human rights concerns, ageing population\n• India\'s family planning programmes: mixed success, regional variations\n• Pro-natalist policies: France, Singapore — modest impact on birth rates\n• Education of women as indirect population policy — very effective\n• Access to contraception and healthcare\n• Financial incentives and disincentives\n• Ethical issues with coercive policies\n• Cultural resistance to population control\n• Unintended consequences: gender imbalance (China, India)\n• Assessment of which approaches have been most successful and ethical' },
      { q: 'Explain the relationship between global health patterns and levels of economic development.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of the relationship with named examples and clear analysis.\nLevel 2 (4-6 marks): Some valid points about health and development.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\n• LICs: infectious diseases dominant — malaria, cholera, HIV/AIDS\n• Limited healthcare infrastructure and access\n• Poor sanitation and clean water access\n• Malnutrition and undernutrition\n• HICs: non-communicable diseases dominant — cancer, heart disease, diabetes\n• Ageing populations create different health challenges\n• Obesity and overnutrition becoming issues\n• Better healthcare systems but still inequalities within countries\n• Epidemiological transition as countries develop\n• Health as both cause and consequence of development\n• Global health inequalities persist despite progress\n• Named examples from HICs and LICs' },
      { q: 'Assess the environmental sustainability of different energy sources.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple energy sources with clear evaluation of sustainability.\nLevel 2 (4-6 marks): Some energy sources discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of energy sources.\n\nIndicative content:\n• Fossil fuels: high carbon emissions, air pollution, finite, but reliable\n• Nuclear: low carbon but waste storage, accident risk, high cost\n• Solar: zero emissions in operation but manufacturing impact, intermittency\n• Wind: low carbon but visual impact, intermittency, bird mortality\n• Hydroelectric: low carbon but ecosystem disruption, displacement\n• Biomass: potentially renewable but land use, emissions in production\n• Geothermal: low impact but geographically limited\n• Assessment of lifecycle environmental impacts\n• Energy storage and grid integration challenges\n• Different contexts require different energy mixes\n• Transition pathways and their feasibility' },
      { q: 'Explain how the concept of ecological footprint can be used to assess environmental sustainability.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of the concept with clear application to sustainability assessment.\nLevel 2 (4-6 marks): Some valid points about ecological footprint.\nLevel 1 (1-3 marks): Basic definition with limited application.\n\nIndicative content:\n• Measures land and water area needed to produce resources and absorb waste\n• Compared with biocapacity — available productive land\n• If footprint exceeds biocapacity → ecological deficit / unsustainable\n• Global ecological footprint exceeds Earth\'s biocapacity by ~70%\n• Variation between countries: USA ~5 planets, India ~0.7 planets\n• Useful for comparing sustainability between nations\n• Highlights consumption inequality\n• Can be broken down by components: food, transport, housing, goods\n• Limitations: doesn\'t capture all environmental impacts\n• Doesn\'t account for quality of life or wellbeing\n• Useful but imperfect tool for sustainability assessment' },
      { q: 'Assess the potential of technology to solve the challenge of feeding a growing global population.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment of technological solutions with consideration of limitations.\nLevel 2 (4-6 marks): Some technologies discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of technologies.\n\nIndicative content:\n• GM crops: higher yields, pest resistance, drought tolerance\n• Precision agriculture: GPS, drones, sensors for efficient farming\n• Vertical farming: year-round production in urban areas\n• Hydroponics and aquaponics: water-efficient food production\n• Lab-grown meat: reduces land and emissions from livestock\n• Irrigation technology: drip irrigation, desalination\n• However: access to technology is unequal\n• Cost barriers for smallholder farmers in LICs\n• Environmental concerns about GM crops\n• Social and cultural resistance\n• Distribution and waste are bigger problems than production\n• Technology alone won\'t solve political and economic barriers\n• Assessment of realistic contribution of technology' },
      { q: 'Explain how natural hazards interact with population vulnerability to create disasters.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation showing how physical hazards and human vulnerability combine, with named examples.\nLevel 2 (4-6 marks): Some valid points about hazard-vulnerability interaction.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\n• A natural hazard alone is not a disaster — requires vulnerable population\n• Vulnerability factors: poverty, population density, governance\n• Exposure: population location relative to hazard zone\n• Capacity: ability to prepare, respond, and recover\n• Environmental degradation increases vulnerability (deforestation → floods)\n• Population growth pushes settlement into marginal/hazardous areas\n• Climate change increasing frequency of climate-related hazards\n• Named examples showing hazard-vulnerability interaction\n• Disaster risk reduction strategies address vulnerability not just hazard\n• Different levels of vulnerability within same hazard zone\n• Risk = Hazard × Vulnerability / Capacity' },

      // 12-20 mark questions (5)
      { q: '"The relationship between population growth and environmental sustainability is the defining challenge of the 21st century." To what extent do you agree?', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated, balanced evaluation considering multiple dimensions of the population-environment relationship. Well-evidenced conclusion.\nLevel 3 (11-15 marks): Good evaluation with relevant evidence.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Global population approaching 10 billion by 2050\n• Resource demands: food, water, energy increasing\n• Climate change driven partly by population and consumption\n• Biodiversity loss from habitat destruction\n• However: consumption patterns matter more than population numbers\n• Wealthiest countries consume disproportionate resources\n• Technology and innovation can reduce environmental impact\n• Population growth is slowing — issue may be transitional\n• Other challenges: inequality, conflict, governance failures\n• Population-environment relationship is complex and mediated\n• Different theoretical perspectives: Malthus vs Boserup\n• IPAT framework: technology and affluence also matter\n• Sustainable development as framework for addressing the challenge\n• Political will and international cooperation as key factors\n• Conclusion on the extent to which this is THE defining challenge' },
      { q: 'Evaluate the strategies available to increase global food security. To what extent can the world feed its growing population sustainably?', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough evaluation of multiple strategies with assessment of their potential and limitations. Well-evidenced conclusion.\nLevel 3 (11-15 marks): Good evaluation with relevant strategies.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Green Revolution: increased yields but environmental costs\n• GM crops: potential but controversial\n• Sustainable intensification: producing more from less\n• Precision agriculture and technology\n• Reducing food waste (30% of food is lost/wasted)\n• Dietary change: reducing meat consumption\n• Land reform and support for smallholders\n• Improved storage, distribution, and infrastructure\n• Climate-smart agriculture\n• Aquaculture and alternative protein sources\n• However: political and economic barriers\n• Trade systems and food sovereignty issues\n• Climate change threatens gains\n• Inequality in access remains key challenge\n• Assessment of whether sustainable feeding is possible\n• Different scales require different strategies' },
      { q: 'Discuss the view that global population policies should focus on reducing consumption rather than reducing population growth.', marks: 20, markScheme: 'Level 4 (16-20 marks): Balanced, well-evidenced discussion considering both approaches. Sophisticated analysis of the consumption-population debate. Well-reasoned conclusion.\nLevel 3 (11-15 marks): Good discussion with relevant evidence.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Arguments for reducing consumption: HICs consume far more per capita\n• Ecological footprint varies hugely — consumption is the key driver\n• Reducing consumption is more equitable than limiting births in LICs\n• Circular economy, efficiency gains can reduce impact\n• Arguments for reducing population growth: absolute numbers matter\n• Even low per-capita consumption × huge population = major impact\n• Family planning empowers women and reduces poverty\n• Population momentum means growth continues for decades\n• Both approaches needed simultaneously\n• Ethical considerations: reproductive rights vs sustainability\n• Historical context: population control policies and their controversies\n• Consumption reduction requires systemic economic change\n• Cultural resistance to both approaches\n• Named examples of policies targeting each approach\n• IPAT equation as framework\n• Conclusion on the balance between the two approaches' },
      { q: 'Evaluate the extent to which water security is the most pressing global resource challenge.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough evaluation comparing water security with other resource challenges. Well-evidenced with detailed examples.\nLevel 3 (11-15 marks): Good evaluation with relevant evidence.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Water stress affecting billions — 2+ billion lack safe drinking water\n• Growing demand from population, agriculture, industry\n• Climate change altering precipitation patterns\n• Transboundary water conflicts potential\n• Water underpins food, energy, and health security\n• However: energy security is also critical — climate change, fossil fuel depletion\n• Food security: feeding 10 billion sustainably\n• Mineral resources: rare earth metals for technology\n• Biodiversity as a resource under threat\n• All resources are interconnected — water-energy-food nexus\n• Regional variation: water most pressing in Middle East/Africa\n• Named examples of water stress: Cape Town, Aral Sea, Colorado River\n• Comparison with other resource challenges\n• Assessment of relative urgency and tractability\n• Conclusion on whether water is the most pressing challenge' },
      { q: 'To what extent can the Demographic Transition Model be used to predict future population change in different parts of the world?', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated evaluation of the DTM\'s predictive value with detailed examples from different regions. Nuanced conclusion.\nLevel 3 (11-15 marks): Good evaluation with relevant examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• DTM describes historical pattern in now-developed countries\n• Successfully predicts declining death rates followed by birth rates\n• Stage 5 addition reflects new HIC patterns\n• Evidence: many countries follow the general pattern\n• However: rate of transition varies hugely\n• Some countries skip stages or transition differently\n• Cultural and religious factors not accounted for\n• HIV/AIDS disrupted the pattern in Sub-Saharan Africa\n• Migration not included in the model\n• Government policies can accelerate or slow transitions\n• Eurocentric model may not apply universally\n• China\'s forced transition vs voluntary transitions\n• LICs may not follow the same path due to different global context\n• Useful as a generalised framework but not a precise predictor\n• Other models and data sources supplement predictions\n• Conclusion on the extent of usefulness for prediction' },
    ],
  },
  '2.4': {
    name: 'Resource Security',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two factors that affect the global demand for energy.', marks: 2, markScheme: '• Population growth / economic development increasing energy consumption (1)\n• Industrialisation / urbanisation / rising living standards / technology use (1)' },
      { q: 'Define the term "energy security".', marks: 2, markScheme: '• The uninterrupted availability of energy sources (1)\n• At an affordable price for a country or population (1)' },
      { q: 'State two advantages of renewable energy sources.', marks: 2, markScheme: '• Do not run out / are sustainable / infinite supply (1)\n• Low or zero carbon emissions during operation / reduce climate change (1)' },
      { q: 'Define the term "resource security".', marks: 2, markScheme: '• The ability of a country or population to access sufficient resources (1)\n• To meet their needs at an affordable and sustainable level (1)' },
      { q: 'State two reasons why some countries are resource-rich but remain economically poor.', marks: 2, markScheme: '• Resource curse — over-reliance on single resource, corruption, conflict (1)\n• Exploitation by transnational corporations / unfair trade terms / lack of infrastructure (1)' },
      { q: 'Define the term "water stress".', marks: 3, markScheme: '• When demand for water exceeds the available supply (1)\n• Or when poor quality restricts its use (1)\n• Often defined as below 1,700 cubic metres per person per year (1)' },
      { q: 'State two ways in which mineral resources are used in everyday life.', marks: 2, markScheme: '• Construction materials (iron, steel, aggregates) for buildings and infrastructure (1)\n• Electronics — rare earth metals in smartphones, computers, batteries (1)' },
      { q: 'Define the term "food miles".', marks: 2, markScheme: '• The distance food is transported from the point of production to the consumer (1)\n• Used as an indicator of the environmental impact of food distribution (1)' },
      { q: 'State two environmental consequences of deforestation.', marks: 2, markScheme: '• Loss of biodiversity / habitat destruction (1)\n• Increased carbon emissions / reduced carbon sink / soil erosion (1)' },
      { q: 'Define the term "virtual water".', marks: 3, markScheme: '• The total volume of water used in the production of goods and services (1)\n• Including the water embedded in the product itself and its supply chain (1)\n• E.g. 15,400 litres of water to produce 1 kg of beef (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain the concept of the energy mix and why it varies between countries.', marks: 6, markScheme: '• Energy mix is the combination of energy sources used by a country (1)\n• Includes fossil fuels, nuclear, and renewable sources (1)\n• Varies due to availability of domestic resources (1)\n• Economic development level affects technology access (1)\n• Government policy and energy security priorities (1)\n• Environmental concerns and climate commitments (1)\n• Historical infrastructure and path dependency (1)\n• Physical geography — potential for hydro, solar, wind (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the causes and consequences of global water inequality.', marks: 6, markScheme: '• Physical causes: climate, geology, precipitation patterns (1)\n• Human causes: population distribution, agriculture, pollution, infrastructure (1)\n• Economic factors: ability to invest in water infrastructure (1)\n• Consequences: health impacts from contaminated water (1)\n• Food insecurity from inability to irrigate (1)\n• Gender inequality — women and girls collect water (1)\n• Conflict over shared water resources (1)\n• Economic development hindered (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the environmental impacts of extracting non-renewable energy resources.', marks: 6, markScheme: '• Surface mining destroys habitats and landscapes (1)\n• Groundwater contamination from mining activities (1)\n• Air pollution from combustion (SO2, NOx, particulates, CO2) (1)\n• Oil spills cause marine and coastal ecosystem damage (1)\n• Fracking can contaminate groundwater and cause minor earthquakes (1)\n• Deforestation for access roads and mining operations (1)\n• Waste products and tailings create pollution (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain why some countries have greater energy security than others.', marks: 5, markScheme: '• Domestic energy resources — oil, gas, coal, renewables (1)\n• Geopolitical stability and reliability of supply routes (1)\n• Diversified energy mix reduces dependence on single source (1)\n• Economic ability to invest in energy infrastructure (1)\n• International agreements and trade relationships (1)\n• Strategic reserves and storage capacity (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain how transnational corporations affect resource security in LICs.', marks: 6, markScheme: '• TNCs extract resources from LICs for global markets (1)\n• Profits may flow out of the country rather than benefiting locals (1)\n• Can provide employment, infrastructure, and technology transfer (1)\n• However: working conditions may be poor and wages low (1)\n• Environmental damage from extraction often borne by local communities (1)\n• Political influence can undermine governance (1)\n• Resource exploitation can fuel conflict (e.g. conflict minerals) (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Describe the global pattern of energy consumption.', marks: 4, markScheme: '• HICs (North America, Europe, Japan) consume most energy per capita (1)\n• Rapidly industrialising countries (China, India) have rapidly growing consumption (1)\n• LICs in Sub-Saharan Africa consume least per capita (1)\n• Middle East oil-producing states have high per-capita consumption (1)\n• Global energy demand has been rising overall (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain the concept of the water-energy-food nexus.', marks: 4, markScheme: '• Water, energy, and food systems are interconnected (1)\n• Water is needed for energy production (cooling, hydropower) and food production (irrigation) (1)\n• Energy is needed for water treatment, pumping, and food processing (1)\n• Food production requires both water and energy (1)\n• Decisions in one sector affect the others (1)\n• Sustainable management requires integrated approach (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain how geopolitics affects access to energy resources.', marks: 6, markScheme: '• Oil and gas concentrated in politically unstable regions (Middle East, Russia) (1)\n• Supply disruption due to conflict or political decisions (1)\n• Pipeline routes create geopolitical dependencies (1)\n• OPEC controls oil supply and pricing decisions (1)\n• Sanctions can restrict energy trade (1)\n• Energy used as political leverage (e.g. Russia-Europe gas) (1)\n• Competition for Arctic resources as ice retreats (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the arguments for and against nuclear energy.', marks: 6, markScheme: 'For:\n• Low carbon emissions during operation (1)\n• Reliable baseload power — not intermittent (1)\n• High energy density — small amount of fuel produces large output (1)\nAgainst:\n• Risk of catastrophic accidents (Chernobyl, Fukushima) (1)\n• Radioactive waste storage for thousands of years (1)\n• High construction and decommissioning costs (1)\n• Security concerns — nuclear proliferation (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the challenges of managing mineral resource extraction sustainably.', marks: 5, markScheme: '• Extraction causes habitat destruction and landscape degradation (1)\n• Water and soil pollution from mining processes (1)\n• Social impacts: displacement, health risks for workers and communities (1)\n• Finite resources — depletion is inevitable (1)\n• Recycling rates remain low for many minerals (1)\n• Governance challenges in many resource-rich LICs (1)\n• Conflict minerals — funding armed groups (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Describe how deforestation affects resource security.', marks: 4, markScheme: '• Loss of timber as a building and fuel resource (1)\n• Soil erosion reduces agricultural productivity — food insecurity (1)\n• Disrupted water cycles — reduced rainfall, increased flood risk (1)\n• Loss of biodiversity — potential loss of medical and genetic resources (1)\n• Reduced carbon storage capacity (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Draw a labelled diagram to show the concept of the water-energy-food nexus.', marks: 4, diagram: true, markScheme: '• Three interconnected elements shown: water, energy, food (1)\n• Arrows showing connections between all three (1)\n• Labels explaining at least two connections (e.g. water for irrigation, energy for pumping) (1)\n• External drivers shown (e.g. population growth, climate change) (1)\n• Credit any valid diagram showing interconnections, max 4 marks' },
      { q: 'Explain how climate change affects water resource availability.', marks: 5, markScheme: '• Changing precipitation patterns — some areas drier, others wetter (1)\n• Glacial melt initially increases then reduces river flows (1)\n• More intense rainfall events but also longer droughts (1)\n• Sea level rise threatens coastal freshwater aquifers (1)\n• Higher temperatures increase evaporation and water demand (1)\n• Seasonal changes in snowmelt timing affect water availability (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain how fair trade schemes can improve resource security for producers in LICs.', marks: 4, markScheme: '• Guaranteed minimum price provides income security (1)\n• Fair trade premium funds community investment (1)\n• Long-term contracts provide stability for planning (1)\n• Encourages sustainable farming practices (1)\n• Empowers producer cooperatives (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain why recycling is important for mineral resource security.', marks: 5, markScheme: '• Finite mineral resources will eventually be depleted (1)\n• Recycling extends the lifespan of available reserves (1)\n• Reduces the need for environmentally damaging extraction (1)\n• Saves energy compared to processing virgin materials (1)\n• Reduces waste going to landfill (1)\n• Strategic importance — reduces dependence on imports (1)\n• Credit any valid points, max 5 marks' },

      // 8-9 mark questions (10)
      { q: 'Assess the potential of renewable energy to achieve global energy security.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of renewable energy potential with evaluation of both advantages and limitations.\nLevel 2 (4-6 marks): Some valid points with partial assessment.\nLevel 1 (1-3 marks): Basic identification of renewable sources.\n\nIndicative content:\n• Solar: abundant, falling costs, but intermittent, land use\n• Wind: mature technology, but intermittent, visual impact\n• Hydroelectric: reliable but limited sites, environmental impact\n• Geothermal: reliable but geographically limited\n• Biomass: renewable but land use, emissions\n• Tidal and wave: predictable but expensive technology\n• Energy storage (batteries) improving but still challenging\n• Grid infrastructure needs upgrading\n• Cost competitiveness improving rapidly\n• However: intermittency remains a major challenge\n• Base load power still needed — nuclear or gas backup\n• Developing countries need affordable energy now\n• Assessment of whether 100% renewable is achievable globally' },
      { q: 'Explain the causes and consequences of the "resource curse" in developing countries.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of causes and consequences with named examples.\nLevel 2 (4-6 marks): Some valid points about the resource curse.\nLevel 1 (1-3 marks): Basic identification of the concept.\n\nIndicative content:\nCauses:\n• Over-reliance on single resource export\n• Volatile commodity prices create economic instability\n• Corruption and rent-seeking behaviour\n• Weak institutions and governance\n• Dutch disease — resource wealth undermines other sectors\n• TNC exploitation and unfair trade terms\nConsequences:\n• Economic inequality despite resource wealth\n• Conflict and political instability\n• Environmental degradation\n• Limited economic diversification\n• Poor investment in education, health, infrastructure\n• Named examples: Nigeria (oil), DR Congo (minerals), Venezuela\n• Assessment of whether the resource curse is inevitable' },
      { q: 'Assess the sustainability of current global food production systems.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment considering environmental, social, and economic dimensions of sustainability.\nLevel 2 (4-6 marks): Some valid points about food production sustainability.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\n• Intensive agriculture: high yields but soil degradation, pollution, emissions\n• Livestock production: significant land use, water use, methane emissions\n• Monoculture: efficient but reduces biodiversity and soil health\n• Pesticide and fertiliser use: productivity gains but environmental costs\n• Food waste: 30% of production lost or wasted\n• Global trade: reduces food miles efficiency\n• Industrial fishing: overfishing and marine ecosystem damage\n• However: feeding 8+ billion people requires productive systems\n• Alternatives: organic, agroecology, permaculture — can they scale?\n• Technology: precision agriculture, vertical farming\n• Assessment of long-term viability of current systems\n• Comparison of different production approaches' },
      { q: 'Explain how international conflict and cooperation relate to resource security.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of both conflict and cooperation with named examples.\nLevel 2 (4-6 marks): Some valid points with examples.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\nConflict:\n• Resource wars — oil in Iraq, minerals in DR Congo\n• Water disputes — Nile, Tigris-Euphrates, Jordan River\n• Competition for Arctic resources\n• Trade disputes and sanctions over resources\n• Resources funding conflict (conflict minerals)\nCooperation:\n• International agreements on resource management\n• OPEC as cooperative pricing mechanism\n• River basin management agreements\n• Technology transfer and knowledge sharing\n• UN Sustainable Development Goals\n• Trade agreements facilitating resource access\n• Assessment of balance between conflict and cooperation' },
      { q: 'Assess the view that economic growth and environmental sustainability are incompatible goals in relation to resource use.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment considering both viewpoints with evidence and examples.\nLevel 2 (4-6 marks): Some consideration of both viewpoints.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\n• Economic growth historically drives resource consumption\n• Environmental Kuznets Curve: pollution may decrease beyond a certain income level\n• Decoupling: can GDP grow without proportional resource increase?\n• Evidence of relative decoupling in some HICs\n• Circular economy model reduces resource use\n• Green growth and sustainable development frameworks\n• However: absolute decoupling not yet achieved globally\n• Rebound effects — efficiency gains consumed by growth\n• Developing countries need economic growth to reduce poverty\n• Degrowth movement questions the growth paradigm\n• Different types of growth have different impacts\n• Assessment of whether compatibility is possible with system change\n• Named examples of green growth initiatives' },
      { q: 'Explain the challenges of transitioning from fossil fuels to renewable energy at a global scale.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple challenges with global perspective.\nLevel 2 (4-6 marks): Some challenges explained.\nLevel 1 (1-3 marks): Basic identification of challenges.\n\nIndicative content:\n• Intermittency of solar and wind — need for storage solutions\n• Massive infrastructure investment required\n• Existing fossil fuel infrastructure represents sunk costs\n• Fossil fuel industry political influence and lobbying\n• Energy-intensive industries difficult to electrify\n• Developing countries need affordable energy for growth\n• Battery technology limitations and mineral requirements\n• Grid modernisation needed for distributed generation\n• Job losses in fossil fuel industries — social impacts\n• International cooperation needed but difficult to achieve\n• Different starting points and resource endowments\n• Just transition considerations — equity and fairness' },
      { q: 'Assess the role of technology in improving resource security.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of technological solutions with evaluation of effectiveness and limitations.\nLevel 2 (4-6 marks): Some technologies discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of technologies.\n\nIndicative content:\n• Desalination technology for water security\n• Renewable energy technology for energy security\n• GM crops and precision agriculture for food security\n• Recycling technology for mineral resource security\n• Fracking unlocked previously inaccessible oil and gas\n• Satellite monitoring of resources and environmental change\n• Smart grids and energy efficiency technology\n• However: technology access is unequal between nations\n• Environmental impacts of technology (e-waste, mining for tech minerals)\n• Cost barriers for LICs\n• Technology alone cannot solve governance and distribution problems\n• Assessment of which technologies have most potential' },
      { q: 'Explain how the concept of sustainability can be applied to water resource management.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of sustainable water management with named examples and strategies.\nLevel 2 (4-6 marks): Some strategies discussed.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\n• Meeting current needs without compromising future availability\n• Demand management: water metering, pricing, efficiency measures\n• Supply management: reservoirs, transfers, desalination\n• Protecting water quality — pollution control\n• Groundwater management — preventing over-abstraction\n• Rainwater harvesting and water recycling\n• Integrated Water Resource Management (IWRM) approach\n• Wetland and watershed protection\n• Agricultural water efficiency — drip irrigation\n• Named examples of sustainable water management\n• Balancing economic, social, and environmental needs\n• Climate change adaptation in water management' },
      { q: 'Assess the environmental and social impacts of large-scale dam construction.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment of both environmental and social impacts with named examples.\nLevel 2 (4-6 marks): Some impacts discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of impacts.\n\nIndicative content:\nEnvironmental:\n• Flooding of habitats and ecosystems behind the dam\n• Disruption of river flow and sediment transport\n• Impact on fish migration and aquatic ecosystems\n• Methane emissions from decomposing vegetation in reservoirs\n• Downstream effects: reduced flooding, sediment starvation\nSocial:\n• Displacement of communities — often indigenous peoples\n• Loss of agricultural land and livelihoods\n• However: reliable water supply for irrigation and drinking\n• Hydroelectric power — clean energy\n• Flood control benefits\n• Named examples: Three Gorges, Aswan, Sardar Sarovar\n• Assessment of whether benefits outweigh costs' },
      { q: 'Explain how changing dietary patterns globally affect food, water, and energy security.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of how dietary changes impact all three resource sectors with clear analysis.\nLevel 2 (4-6 marks): Some valid points about diet and resources.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\n• Rising global middle class increasing demand for meat and dairy\n• Meat production requires far more land, water, and energy per calorie\n• 1 kg beef = ~15,400 litres of water vs 1,800 for wheat\n• Livestock account for ~14.5% of greenhouse gas emissions\n• Grain fed to livestock could feed more people directly\n• Processed food requires more energy for production and transport\n• However: dietary change in opposite direction could improve security\n• Plant-based diets use fewer resources per person\n• Food waste reduction could significantly improve security\n• Cultural and economic barriers to dietary change\n• Water-energy-food nexus illustrated through dietary choices\n• Assessment of impact of current trends and potential for change' },

      // 12-20 mark questions (5)
      { q: '"Global resource security can only be achieved through international cooperation, not competition." Discuss this statement.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough, balanced discussion considering both cooperation and competition with multiple named examples. Well-reasoned conclusion.\nLevel 3 (11-15 marks): Good discussion with relevant examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• International cooperation: UN SDGs, Paris Agreement, water treaties\n• Shared management of transboundary resources\n• Technology transfer and capacity building\n• Fair trade and equitable resource distribution\n• However: national interest often prioritises competition\n• Resource nationalism — countries securing their own supply\n• Geopolitical competition for oil, gas, minerals\n• Water conflicts — Nile, Mekong, Middle East\n• Economic competition drives resource exploitation\n• Free trade vs protectionism in resource markets\n• Power imbalances make "cooperation" unequal\n• Some resources are genuinely scarce — zero-sum competition\n• Mixed approach: cooperation on some issues, competition on others\n• Role of TNCs — neither national nor cooperative\n• Named examples of successful cooperation and destructive competition\n• Conclusion on the balance needed between cooperation and competition' },
      { q: 'Evaluate the extent to which the transition to renewable energy is achievable and desirable at a global scale.', marks: 20, markScheme: 'Level 4 (16-20 marks): Comprehensive evaluation considering technical, economic, social, and political dimensions. Well-evidenced with global perspective.\nLevel 3 (11-15 marks): Good evaluation with relevant evidence.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\nAchievability:\n• Rapidly falling costs of solar and wind\n• Technology improving (battery storage, smart grids)\n• Countries achieving high renewable shares (Denmark, Costa Rica)\n• However: intermittency, storage, grid challenges\n• Hard-to-decarbonise sectors (heavy industry, aviation)\n• Mineral requirements for batteries and technologies\n• Infrastructure investment scale needed\nDesirability:\n• Climate change mitigation imperative\n• Air quality and health benefits\n• Energy independence and security\n• Job creation in green economy\n• However: transition costs and economic disruption\n• Social impacts on fossil fuel communities\n• Developing countries need affordable energy now\n• Just transition principles and equity considerations\n• Different pathways for different countries\n• Conclusion on achievability and desirability with nuanced assessment' },
      { q: 'To what extent do the benefits of global food trade outweigh its costs? Use named examples in your answer.', marks: 20, markScheme: 'Level 4 (16-20 marks): Balanced evaluation of benefits and costs with multiple named examples. Detailed understanding of global food systems.\nLevel 3 (11-15 marks): Good evaluation with named examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\nBenefits:\n• Access to diverse food year-round\n• Economies of scale reduce costs\n• Comparative advantage — countries produce what they\'re best at\n• Income for LIC food exporters\n• Food availability during local shortages\n• Consumer choice and dietary diversity\nCosts:\n• Food miles and carbon emissions from transport\n• Cash crop production at expense of local food security\n• Unfair trade terms disadvantaging LIC producers\n• Loss of local food cultures and diversity\n• TNC control of food supply chains\n• Vulnerability to supply chain disruption\n• Environmental costs of industrial agriculture for export\n• Named examples: coffee, bananas, soy, palm oil trade\n• Fair trade as attempt to address inequities\n• Food sovereignty movement arguments\n• COVID-19 exposed vulnerabilities of global food trade\n• Conclusion on balance of benefits and costs' },
      { q: 'Discuss the challenges and opportunities of managing resources sustainably in a world of growing demand.', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated discussion covering multiple resource types with evaluation of challenges and opportunities. Well-evidenced conclusion.\nLevel 3 (11-15 marks): Good discussion with relevant evidence.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\nChallenges:\n• Population growth to ~10 billion increasing demand\n• Rising consumption with economic development\n• Climate change affecting resource availability\n• Finite nature of mineral and fossil fuel resources\n• Governance failures and corruption in resource management\n• Inequality in resource access and consumption\n• Short-term economic pressures vs long-term sustainability\nOpportunities:\n• Circular economy reducing waste and resource use\n• Technology improving efficiency and enabling substitution\n• Renewable energy replacing fossil fuels\n• Sustainable agriculture and aquaculture\n• Recycling and resource recovery\n• International cooperation frameworks\n• Consumer behaviour change\n• Named examples from different resource sectors\n• Assessment of whether sustainable management is achievable\n• Role of governance, technology, and behaviour change' },
      { q: 'Evaluate the view that mineral resource extraction inevitably leads to environmental degradation and social injustice.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough evaluation considering evidence for and against the statement. Multiple named examples with nuanced conclusion.\nLevel 3 (11-15 marks): Good evaluation with examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Evidence for: mining causes deforestation, water pollution, landscape scarring\n• Health impacts on workers and local communities\n• Displacement of indigenous peoples\n• Conflict minerals fuelling armed conflict (DR Congo)\n• Environmental justice issues — impacts fall on poorest communities\n• Tailings dam failures (Brumadinho, Brazil)\n• However: extraction can be managed more responsibly\n• Environmental regulations in HICs reduce impacts\n• Rehabilitation and land restoration after mining\n• Corporate social responsibility programmes\n• Employment and economic benefits for local communities\n• Essential for modern life — renewable energy needs minerals too\n• Recycling reduces need for new extraction\n• Certification schemes (e.g. conflict-free minerals)\n• Technology reducing environmental impact of extraction\n• Assessment of whether "inevitably" is accurate\n• Conclusion considering conditions under which impacts can be minimised' },
    ],
  },
  '3.1': {
    name: 'Fieldwork & Investigation',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two advantages of using systematic sampling in geographical fieldwork.', marks: 2, markScheme: '• Gives good spatial coverage of the study area (1)\n• Reduces researcher bias in selecting sample points (1)' },
      { q: 'Define the term "primary data" in the context of geographical fieldwork.', marks: 2, markScheme: '• Data collected first-hand/directly by the researcher (1)\n• In the field or through original surveys, measurements, and observations (1)' },
      { q: 'State two reasons why risk assessments are important in geographical fieldwork.', marks: 2, markScheme: '• Identifies potential hazards that could cause harm to participants (1)\n• Allows mitigation strategies to be planned to reduce risk (1)' },
      { q: 'Define the term "qualitative data".', marks: 2, markScheme: '• Non-numerical data that describes qualities, characteristics, or opinions (1)\n• E.g. photographs, interview transcripts, field sketches, descriptions (1)' },
      { q: 'State two limitations of using questionnaires in geographical fieldwork.', marks: 2, markScheme: '• Responses may be biased or dishonest (1)\n• Sample may not be representative of the whole population / low response rate (1)' },
      { q: 'Define the term "random sampling".', marks: 3, markScheme: '• A sampling method where every item/location has an equal chance of being selected (1)\n• Selection is determined by random number generation or equivalent method (1)\n• Removes human bias from the sampling process (1)' },
      { q: 'State two types of data presentation that could be used to display spatial data.', marks: 2, markScheme: '• Choropleth map (1)\n• Isoline map / dot map / proportional symbol map / flow map / GIS mapping (1)' },
      { q: 'Define the term "secondary data" and give one example.', marks: 3, markScheme: '• Data that has already been collected by someone else / not first-hand (1)\n• Obtained from published or existing sources (1)\n• Example: census data, OS maps, satellite imagery, published reports (1)' },
      { q: 'State two factors that should be considered when choosing a fieldwork location.', marks: 2, markScheme: '• Relevance to the research question / hypothesis (1)\n• Safety and accessibility / permission / practical logistics (1)' },
      { q: 'Define the term "reliability" in the context of geographical investigation.', marks: 2, markScheme: '• The extent to which data collection methods produce consistent results (1)\n• If repeated under the same conditions by different researchers (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain the advantages and disadvantages of stratified sampling compared to random sampling.', marks: 6, markScheme: '• Stratified: population divided into subgroups/strata, samples taken from each (1)\n• Ensures all subgroups are represented in the sample (1)\n• More representative than simple random sampling (1)\n• However: requires prior knowledge of population characteristics (1)\n• More complex and time-consuming to set up (1)\n• Random: simple, unbiased, but may miss key subgroups (1)\n• Random may over-represent some areas and under-represent others (1)\n• Credit any valid comparative points, max 6 marks' },
      { q: 'Explain why it is important to use both quantitative and qualitative data in a geographical investigation.', marks: 4, markScheme: '• Quantitative data provides measurable, objective evidence (1)\n• Can be statistically analysed and compared (1)\n• Qualitative data provides depth, meaning, and context (1)\n• Captures human experiences and perceptions that numbers cannot (1)\n• Combining both provides a more complete picture — triangulation (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Explain how you would design a sampling strategy for a river study investigating changes in river characteristics downstream.', marks: 6, markScheme: '• Systematic sampling along the river at regular intervals (1)\n• Selecting sites based on accessibility and safety (1)\n• Multiple measurements at each site for reliability (1)\n• Measuring width, depth, velocity, and sediment at each point (1)\n• Recording coordinates and mapping sample locations (1)\n• Justification: systematic captures the downstream trend (1)\n• Random element within each site for measuring positions (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the ethical considerations that should be taken into account when conducting geographical fieldwork involving people.', marks: 5, markScheme: '• Informed consent — participants must agree to take part (1)\n• Anonymity and confidentiality of responses (1)\n• Right to withdraw at any time without reason (1)\n• Avoiding sensitive or intrusive questions (1)\n• Cultural sensitivity — respecting local customs and norms (1)\n• Data protection — secure storage and appropriate use of data (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain how the Spearman\'s rank correlation coefficient can be used to analyse geographical data.', marks: 6, markScheme: '• Tests the strength and direction of relationship between two variables (1)\n• Both variables must be at least ordinal/ranked data (1)\n• Values range from -1 (perfect negative) to +1 (perfect positive) (1)\n• 0 indicates no correlation (1)\n• Significance tested against critical values for the sample size (1)\n• Example application: distance from CBD vs land values (1)\n• Does not prove causation — only shows association (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain how you could use GIS to investigate a geographical question.', marks: 5, markScheme: '• GIS allows layering of multiple data sets onto a map base (1)\n• Can overlay physical and human data to identify patterns (1)\n• Spatial analysis tools identify relationships and clusters (1)\n• Example: overlaying flood risk zones with population density (1)\n• Enables precise measurement and spatial analysis (1)\n• Can display results as professional maps for presentation (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Describe how you would present river velocity data collected at multiple sites using appropriate graphical methods.', marks: 4, markScheme: '• Scatter graph showing distance downstream (x) vs velocity (y) (1)\n• Line of best fit to show the trend (1)\n• Cross-section diagram showing velocity variation across the channel (1)\n• Located proportional symbols on a map showing velocity at each site (1)\n• Box and whisker plots to compare velocity distributions between sites (1)\n• Credit any valid methods with justification, max 4 marks' },
      { q: 'Explain how you would evaluate the accuracy and reliability of data collected during a fieldwork investigation.', marks: 6, markScheme: '• Accuracy: comparing results with published data or known values (1)\n• Repeating measurements to check for consistency (1)\n• Using calibrated equipment and standardised methods (1)\n• Large enough sample size to be representative (1)\n• Multiple data collection methods for triangulation (1)\n• Identifying and acknowledging sources of error (1)\n• Considering whether different researchers would get similar results (1)\n• Credit any valid points, max 6 marks' },
      { q: 'Explain the advantages of using ICT and digital technology in geographical fieldwork.', marks: 5, markScheme: '• GPS provides accurate location data for mapping (1)\n• Digital data loggers record measurements precisely and consistently (1)\n• GIS enables sophisticated spatial analysis (1)\n• Data can be processed and analysed quickly using software (1)\n• Digital photography provides visual evidence (1)\n• Online databases provide secondary data for comparison (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Describe and justify appropriate methods for collecting data on pedestrian flows in a town centre.', marks: 6, markScheme: '• Pedestrian count at multiple locations using tally charts (1)\n• Systematic timing — count for same duration at each site (1)\n• Multiple counts at different times of day for reliability (1)\n• Gate count method — counting people crossing a line (1)\n• Recording on a base map of the town centre (1)\n• Justification: quantitative data allows statistical comparison between sites (1)\n• Standardised method ensures comparability (1)\n• Credit any valid methods with justification, max 6 marks' },
      { q: 'Explain how the chi-squared test could be used in a geographical investigation.', marks: 5, markScheme: '• Tests whether there is a significant difference between observed and expected frequencies (1)\n• Data must be in categories/nominal form (1)\n• Null hypothesis: there is no significant difference (1)\n• Calculated value compared with critical value at chosen significance level (1)\n• Example: comparing land use types in different zones of a town (1)\n• Degrees of freedom calculated from number of categories (1)\n• Credit any valid points, max 5 marks' },
      { q: 'Explain the importance of having a clear research question and hypothesis in geographical fieldwork.', marks: 4, markScheme: '• Provides focus and direction for the investigation (1)\n• Determines what data needs to be collected (1)\n• Hypothesis can be tested through data collection and analysis (1)\n• Enables evaluation of findings against the original question (1)\n• Helps justify the methodology chosen (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Sketch an annotated field sketch of a geographical feature you might encounter during coastal fieldwork.', marks: 5, diagram: true, markScheme: '• Recognisable sketch of a coastal feature (cliff, beach, sand dunes, etc.) (1)\n• Key features labelled correctly (1)\n• Annotations explaining processes or characteristics (1)\n• Scale or perspective indicated (1)\n• Title and location information (1)\n• Credit any well-annotated field sketch, max 5 marks' },
      { q: 'Explain how you would use secondary data sources to support a geographical investigation.', marks: 4, markScheme: '• Census data provides demographic context (1)\n• OS maps provide spatial context and base mapping (1)\n• Published research provides theoretical framework (1)\n• Historical data enables comparison over time (1)\n• Secondary data complements primary data for triangulation (1)\n• Credit any valid points, max 4 marks' },
      { q: 'Describe appropriate methods for measuring river discharge at a field site.', marks: 6, markScheme: '• Measure channel width using a tape measure (1)\n• Measure depth at regular intervals across the channel (1)\n• Calculate cross-sectional area from width and depth data (1)\n• Measure velocity using a flow meter or float method (1)\n• Take multiple velocity readings at each point (e.g. 0.6 depth) (1)\n• Discharge = cross-sectional area × mean velocity (1)\n• Repeat at multiple sites for downstream comparison (1)\n• Credit any valid methods, max 6 marks' },

      // 8-9 mark questions (10)
      { q: 'Assess the extent to which your geographical investigation produced valid and reliable conclusions.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed, reflective assessment of validity and reliability with specific examples from own investigation.\nLevel 2 (4-6 marks): Some consideration of validity and reliability.\nLevel 1 (1-3 marks): Basic comments on data quality.\n\nIndicative content:\n• Specific reference to own investigation and methodology\n• Validity: did the investigation measure what it intended to?\n• Were data collection methods appropriate for the research question?\n• Were sample sizes adequate?\n• Were there sources of bias in data collection?\n• Reliability: would results be consistent if repeated?\n• Standardised methods improve reliability\n• Calibration of equipment\n• Triangulation of multiple data sources\n• Limitations acknowledged and their impact on conclusions\n• What could be improved to strengthen validity and reliability\n• Assessment of confidence in the conclusions drawn' },
      { q: 'Explain the factors that influenced the design of a geographical investigation you have undertaken.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of multiple design factors with specific reference to own investigation.\nLevel 2 (4-6 marks): Some factors explained with reference to own work.\nLevel 1 (1-3 marks): Basic identification of factors.\n\nIndicative content:\n• Research question/hypothesis and its requirements\n• Theoretical framework informing the approach\n• Practical constraints: time, equipment, access, weather\n• Safety considerations and risk assessment\n• Sampling strategy and its justification\n• Choice of data collection methods — why these and not others\n• Ethical considerations (if involving people)\n• Scale of investigation — local, transect, etc.\n• Data presentation and analysis methods planned\n• Previous studies or published evidence influencing design\n• How design was modified during fieldwork\n• Specific details from own investigation' },
      { q: 'Assess the strengths and limitations of the data presentation methods you used in a geographical investigation.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple presentation methods with evaluation of their effectiveness.\nLevel 2 (4-6 marks): Some methods discussed with partial assessment.\nLevel 1 (1-3 marks): Basic identification of methods.\n\nIndicative content:\n• Specific presentation methods used in own investigation\n• Graphs: scatter plots, bar charts, line graphs — clear visual patterns\n• Maps: show spatial distribution effectively\n• Tables: precise data but less visual\n• Statistical techniques: objective analysis of relationships\n• Photographs and field sketches: visual evidence\n• Strengths: clarity, ability to show patterns and relationships\n• Limitations: may oversimplify, selective presentation\n• Appropriateness of each method for the data type\n• How presentation methods helped draw conclusions\n• What alternative methods could have been used\n• Assessment of overall effectiveness of data presentation' },
      { q: 'Explain how you used statistical analysis in a geographical investigation, and evaluate its usefulness.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of statistical methods with evaluation of their usefulness in the investigation.\nLevel 2 (4-6 marks): Some explanation of statistical methods.\nLevel 1 (1-3 marks): Basic identification of statistics used.\n\nIndicative content:\n• Specific statistical test(s) used and why chosen\n• Spearman\'s rank, chi-squared, Mann-Whitney, or others\n• Null hypothesis and significance level explained\n• How the test was applied to the data\n• Results and interpretation of the test\n• Whether results were statistically significant\n• How statistics supported or refuted the hypothesis\n• Strengths: objective, reduces bias, quantifies relationships\n• Limitations: small sample sizes reduce power\n• Assumptions of the test and whether they were met\n• Statistical significance vs practical significance\n• Overall evaluation of the contribution of statistics to the investigation' },
      { q: 'Assess the extent to which your chosen methodology was appropriate for answering your research question.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed, reflective assessment linking methodology to research question with critical evaluation.\nLevel 2 (4-6 marks): Some reflection on methodology.\nLevel 1 (1-3 marks): Basic comments.\n\nIndicative content:\n• Clear statement of research question\n• Methodology described and justified\n• How data collection methods addressed the question\n• Sampling strategy and its appropriateness\n• Equipment and techniques used\n• What worked well and why\n• What could be improved\n• Alternative approaches that could have been taken\n• Practical constraints that affected methodology\n• Whether the data collected was sufficient to answer the question\n• How limitations of the methodology affected conclusions\n• Assessment of overall appropriateness' },
      { q: 'Explain how you would improve a geographical investigation if you were to repeat it.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed, reflective discussion of specific improvements with clear justification.\nLevel 2 (4-6 marks): Some improvements identified with partial justification.\nLevel 1 (1-3 marks): Basic suggestions.\n\nIndicative content:\n• Increase sample size for greater reliability\n• Use more sophisticated equipment for accuracy\n• Improve sampling strategy — different method or more sites\n• Collect data at different times/seasons for comparison\n• Add additional variables or data types\n• Improve questionnaire design\n• Use additional statistical tests\n• Better data presentation methods\n• Address specific sources of error identified\n• Expand geographical scope\n• Incorporate more secondary data for context\n• Each improvement must be justified with reasoning' },
      { q: 'Assess the role of human and physical geography in shaping the conclusions of your fieldwork investigation.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment showing understanding of both human and physical influences on investigation findings.\nLevel 2 (4-6 marks): Some consideration of geographical influences.\nLevel 1 (1-3 marks): Basic points.\n\nIndicative content:\n• Specific reference to own investigation\n• Physical factors: geology, climate, hydrology, topography\n• Human factors: land use, management, development, population\n• How these factors influenced the data collected\n• Interaction between physical and human factors\n• Whether conclusions reflected expected theoretical patterns\n• Anomalies and how they relate to local physical/human conditions\n• Scale of investigation and its influence on conclusions\n• How context-specific the conclusions are\n• Transferability of findings to other locations\n• Assessment of relative importance of physical vs human factors' },
      { q: 'Explain how you ensured ethical practice throughout a geographical investigation.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of ethical considerations with specific examples from own fieldwork.\nLevel 2 (4-6 marks): Some ethical considerations discussed.\nLevel 1 (1-3 marks): Basic identification of ethical issues.\n\nIndicative content:\n• Informed consent from participants in surveys/interviews\n• Anonymity and confidentiality of respondents\n• Minimising environmental impact during fieldwork\n• Respecting private property and permissions\n• Risk assessment protecting participants and researchers\n• Cultural sensitivity in questions and interactions\n• Data protection and secure storage\n• Honest reporting of results — not cherry-picking data\n• Acknowledging sources and avoiding plagiarism\n• Consideration of how findings might affect communities studied\n• Specific examples of ethical decisions made during the investigation' },
      { q: 'Assess the challenges of conducting independent fieldwork and how these can be overcome.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of multiple challenges with practical strategies for overcoming them.\nLevel 2 (4-6 marks): Some challenges discussed with partial solutions.\nLevel 1 (1-3 marks): Basic identification of challenges.\n\nIndicative content:\n• Time constraints — limited fieldwork days\n• Weather conditions affecting data collection\n• Equipment availability and reliability\n• Safety considerations — lone working\n• Access to study sites and permissions\n• Maintaining objectivity and avoiding bias\n• Sample size limitations\n• Dealing with unexpected findings\n• Solutions: careful planning, risk assessment\n• Pilot studies to test methods\n• Flexible methodology that can adapt\n• Multiple data collection methods for triangulation\n• Use of secondary data to supplement primary\n• Working in pairs/groups for safety and reliability' },
      { q: 'Explain how the findings of your geographical investigation connect to wider geographical theory and knowledge.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation linking findings to relevant geographical theory with evaluation.\nLevel 2 (4-6 marks): Some links to theory.\nLevel 1 (1-3 marks): Basic reference to theory.\n\nIndicative content:\n• Specific reference to own investigation and findings\n• Named geographical theory or model relevant to the investigation\n• How findings support or challenge the theory\n• Links to published research on the same topic\n• How findings relate to broader geographical processes\n• Scale — how local findings relate to regional/global patterns\n• Whether findings are consistent with expected outcomes\n• Anomalies and how they relate to theoretical understanding\n• Contribution of the investigation to geographical knowledge\n• Limitations of applying theory to specific local contexts\n• How the investigation deepened understanding of the topic' },

      // 12-20 mark questions (5)
      { q: 'Evaluate the extent to which the methodology you used in your independent investigation allowed you to reach valid conclusions about a geographical question.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough, reflective evaluation of the entire methodology with detailed assessment of validity. Well-structured response demonstrating understanding of investigative process.\nLevel 3 (11-15 marks): Good evaluation with relevant detail from own investigation.\nLevel 2 (6-10 marks): Some evaluation of methodology.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Clear statement of research question and hypothesis\n• Justification of chosen methodology\n• Sampling strategy — type, size, rationale\n• Data collection methods — strengths and limitations\n• Equipment used and its accuracy\n• Consideration of practical constraints\n• Data presentation methods and their appropriateness\n• Statistical analysis and what it revealed\n• Validity of conclusions — do they answer the question?\n• Sources of error and their impact\n• How methodology could be improved\n• Comparison with alternative approaches\n• Links between methodology, data quality, and conclusion validity\n• Reflective assessment of the overall investigation process' },
      { q: '"The value of geographical fieldwork lies not in the data collected but in the skills and understanding developed through the process." Discuss this statement.', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated discussion considering both the data and the process dimensions of fieldwork. Balanced, evaluative conclusion.\nLevel 3 (11-15 marks): Good discussion with relevant reflections.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Data value: provides evidence for answering questions, tests hypotheses\n• Quantitative data enables statistical analysis and conclusions\n• Qualitative data provides depth and understanding\n• Data can contribute to wider geographical knowledge\n• Process value: develops practical skills (measurement, observation)\n• Analytical skills: data processing, statistical analysis\n• Critical thinking: evaluating methodology, questioning assumptions\n• Teamwork and communication skills\n• Understanding of real-world geographical processes\n• Application of theoretical knowledge to real situations\n• Problem-solving when things don\'t go to plan\n• Developing independence and self-management\n• Both data and process are valuable — not either/or\n• Process skills are transferable; data may be context-specific\n• Conclusion on the relative value of data vs process' },
      { q: 'To what extent is it possible to conduct a fully objective geographical investigation? Discuss with reference to your own fieldwork.', marks: 20, markScheme: 'Level 4 (16-20 marks): Sophisticated epistemological discussion with detailed examples from own fieldwork. Nuanced conclusion about objectivity.\nLevel 3 (11-15 marks): Good discussion with relevant examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Quantitative methods aim for objectivity — measurements, statistics\n• Standardised methods improve consistency\n• However: choice of research question reflects researcher\'s values\n• Sampling decisions involve subjective judgement\n• Measurement involves human error and interpretation\n• Qualitative data is inherently subjective\n• Researcher\'s background influences perception and analysis\n• Selective data presentation can introduce bias\n• Ethical choices involve subjective judgement\n• Specific examples from own fieldwork showing subjective elements\n• Strategies to improve objectivity: standardisation, triangulation, statistical testing\n• However: complete objectivity is probably impossible\n• This is not unique to geography — applies to all research\n• Value of acknowledging subjectivity rather than pretending objectivity\n• Conclusion: strive for objectivity while acknowledging limitations' },
      { q: 'Evaluate the role of technology in enhancing the quality and outcomes of geographical fieldwork investigations.', marks: 20, markScheme: 'Level 4 (16-20 marks): Thorough evaluation of multiple technologies with assessment of their impact on fieldwork quality. Balanced conclusion.\nLevel 3 (11-15 marks): Good evaluation with relevant examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• GPS: accurate location recording, mapping\n• Digital data loggers: precise, consistent measurements\n• GIS: sophisticated spatial analysis, data layering\n• Spreadsheets: rapid data processing and analysis\n• Statistical software: complex analysis possible\n• Digital photography and video: visual evidence\n• Drones: aerial photography and mapping\n• Smartphones: multi-purpose data collection tools\n• Online databases for secondary data\n• However: technology can fail in the field\n• Cost and access barriers\n• Over-reliance on technology — lack of understanding\n• Traditional methods still valuable (field sketches, observation)\n• Data quality depends on method, not just technology\n• Technology cannot replace geographical understanding\n• Named examples from own fieldwork\n• Conclusion on the extent to which technology enhances quality' },
      { q: 'Discuss the importance of understanding geographical processes and theories when designing and carrying out fieldwork investigations.', marks: 20, markScheme: 'Level 4 (16-20 marks): Detailed discussion showing how theoretical understanding shapes every stage of investigation. Well-structured with examples from own fieldwork.\nLevel 3 (11-15 marks): Good discussion with relevant examples.\nLevel 2 (6-10 marks): Some relevant points.\nLevel 1 (1-5 marks): Basic, limited response.\n\nIndicative content:\n• Theory informs the research question — what to investigate\n• Hypothesis derived from theoretical understanding\n• Knowledge of processes determines what to measure\n• Understanding of models guides expected outcomes\n• Methodology informed by how processes operate\n• Sampling designed to capture geographical variation\n• Data analysis interpreted through theoretical lens\n• Anomalies recognised because expected pattern is known\n• Conclusions related back to theory — does evidence support it?\n• Without theoretical understanding, fieldwork is just data collection\n• Theory provides the "why" behind the observations\n• However: fieldwork can challenge and update theory\n• Inductive approaches build theory from observation\n• Balance between deductive and inductive approaches\n• Named examples from own fieldwork\n• Conclusion on the essential role of theory in fieldwork' },
    ],
  },
};
